INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('5a75f6d0-3fc8-48e1-ba61-671d194e377c', 'A-001', 'apprentice', 'nec-navigation', 'NEC Navigation', 'A question depends on the NEC meaning of the term ''readily accessible.'' Which location should you check first?', '{"A":"Article 100","B":"Article 110","C":"Article 210","D":"Annex D"}'::jsonb, 'A', 'Defined terms should be checked in Article 100 before you interpret the installation rule. That prevents using an everyday meaning when the NEC has a technical one.', 'Article 100', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('4b900bd4-02af-4ce8-ba31-59eb8b5cd825', 'A-002', 'apprentice', 'safety', 'Safety', 'Which NEC section is commonly used for questions about required working space around electrical equipment?', '{"A":"110.12","B":"110.14","C":"110.26","D":"300.4"}'::jsonb, 'C', 'Section 110.26 addresses access and working space around electrical equipment. It is one of the most common general-requirement lookup points on electrician exams.', '110.26', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('91851f5c-ebff-4fa6-9781-e3a1a3a3cce1', 'A-003', 'apprentice', 'branch-circuits', 'Branch Circuits', 'In dwelling-unit habitable rooms, receptacle placement rules are found primarily in which section?', '{"A":"210.52(A)","B":"220.12","C":"250.24","D":"314.16"}'::jsonb, 'A', 'Section 210.52(A) addresses dwelling-unit receptacle spacing requirements for wall spaces in habitable rooms.', '210.52(A)', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('668e8856-2a44-48ec-afeb-9401ca83cbd0', 'A-004', 'apprentice', 'boxes-and-fittings', 'Boxes and Fittings', 'Box-fill calculations for conductor volume are found in which NEC section?', '{"A":"300.11","B":"310.16","C":"314.16","D":"430.52"}'::jsonb, 'C', 'Section 314.16 covers box volume and conductor-fill requirements. This is a core apprentice code-lookup topic.', '314.16', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('5e2149bc-9bb8-4f92-8f94-53b9d66714d6', 'A-005', 'apprentice', 'conductors', 'Conductors', 'Which NEC table is commonly used to look up general conductor ampacity values before applying adjustment or correction factors?', '{"A":"250.66","B":"310.16","C":"430.250","D":"Table 8, Chapter 9"}'::jsonb, 'B', 'Table 310.16 is the common starting point for general conductor ampacity lookup. The user must still read the surrounding sections and applicable conditions.', '310.16', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('65ae810c-c97f-4fd7-92d9-d6489eb2ac6d', 'J-001', 'journeyman', 'continuous-load', 'Continuous Load', 'Under the NEC, a continuous load is one where the maximum current is expected to continue for how long?', '{"A":"30 minutes or more","B":"1 hour or more","C":"2 hours or more","D":"3 hours or more"}'::jsonb, 'D', 'Article 100 defines a continuous load as one where the maximum current is expected to continue for 3 hours or more.', 'Article 100', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('36ba6ad2-7237-45d3-beac-7afeb842a6c4', 'J-002', 'journeyman', 'branch-circuits-and-feeders', 'Branch Circuits and Feeders', 'A branch circuit supplies a 40-ampere continuous load and no noncontinuous load. Ignoring conductor-terminal limitations and using the NEC continuous-load rule, what is the minimum overcurrent device rating to consider first?', '{"A":"40 A","B":"45 A","C":"50 A","D":"60 A"}'::jsonb, 'C', 'For a continuous load, start with 125 percent: 40 x 1.25 = 50 A. The code path then continues through the applicable overcurrent and conductor rules.', '210.20(A)', 'intermediate', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('3760cb1b-92ee-48a5-9012-b3360d4d080b', 'J-003', 'journeyman', 'grounding-and-bonding', 'Grounding and Bonding', 'Which NEC section should you check when a feeder supplies a separate building or structure?', '{"A":"250.24","B":"250.32","C":"250.50","D":"300.3"}'::jsonb, 'B', 'Section 250.32 addresses buildings or structures supplied by feeder or branch circuit. Candidates often miss this by staying in the service-equipment section.', '250.32', 'intermediate', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('5261dd7c-e9d9-4e85-816b-233bd0a657df', 'J-004', 'journeyman', 'motors', 'Motors', 'When sizing motor branch-circuit conductors, electricians are often directed to use what value rather than only the nameplate current?', '{"A":"Service demand load","B":"Full-load current from the applicable NEC table","C":"Largest branch-circuit overcurrent device","D":"Equipment grounding conductor ampacity"}'::jsonb, 'B', 'Motor conductor and protection rules often rely on the applicable NEC full-load current tables rather than only the nameplate current. Journeyman candidates should know where to find those motor tables and rules.', '430.22', 'intermediate', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('020c0bd1-8d53-472a-91fe-add63a110ed8', 'J-005', 'journeyman', 'load-calculations', 'Load Calculations', 'Which article is the main starting point for feeder and service load calculations?', '{"A":"Article 220","B":"Article 250","C":"Article 300","D":"Article 430"}'::jsonb, 'A', 'Article 220 contains the load-calculation rules used before moving to conductor and overcurrent sizing articles.', 'Article 220', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('cc6e0145-a9f3-46a7-a1eb-ddb3ef10698f', 'M-001', 'master', 'load-calculations', 'Load Calculations', 'Before starting a dwelling optional calculation problem, what should a master candidate determine first?', '{"A":"The conductor insulation rating","B":"Whether the occupancy qualifies for the optional method being used","C":"The grounding electrode type","D":"The available fault current"}'::jsonb, 'B', 'The first step is determining that the optional method applies. If the wrong method is chosen, the rest of the calculation can be invalid even if the arithmetic is correct.', '220.82', 'intermediate', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('26de374c-3e15-4232-974d-b68431f64dc4', 'M-002', 'master', 'hazardous-locations', 'Hazardous Locations', 'In a hazardous-location problem, what should generally be established before selecting equipment or fittings?', '{"A":"The box-fill volume","B":"The service conductor size","C":"The classification of the location","D":"The panelboard directory format"}'::jsonb, 'C', 'Classification comes first. Once the Class, Division, or Zone is known, the candidate can move to the appropriate equipment and wiring-method rules.', '500.5', 'intermediate', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('913cbddc-ce72-4f93-83ae-a7d52695e739', 'M-003', 'master', 'code-interpretation', 'Code Interpretation', 'Which NEC section is commonly used to explain the hierarchy between general rules and rules for special occupancies, equipment, or conditions?', '{"A":"90.3","B":"110.14","C":"220.40","D":"250.66"}'::jsonb, 'A', 'Section 90.3 explains the arrangement of the Code and the relationship between Chapters 1 through 4 and the special rules in Chapters 5 through 7.', '90.3', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('ceb38cfc-60be-459e-9944-ddc16882236e', 'M-004', 'master', '2026-nec-changes', '2026 NEC Changes', 'According to official NFPA development material for the 2026 NEC, which new article was created to address grounding and bonding of systems over 1000 Vac and 1500 Vdc nominal?', '{"A":"Article 245","B":"Article 270","C":"Article 495","D":"Article 627"}'::jsonb, 'B', 'NFPA working-draft material for the 2026 cycle shows the creation of Article 270 for grounding and bonding of systems over 1000 Vac and 1500 Vdc nominal.', '2026 NFPA development material for Article 270', 'advanced', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('77a91ac3-99ed-4361-926c-6209a2222663', 'M-005', 'master', 'special-equipment', 'Special Equipment', 'Official NFPA public-input material for the 2026 cycle proposed a new Article 627 primarily to address power transfer for what broad category?', '{"A":"Swimming pools and spas","B":"Electric self-propelled vehicles beyond standard on-road EV coverage","C":"Hospitals only","D":"Temporary wiring on construction sites"}'::jsonb, 'B', 'NFPA 2026 public-input records describe Article 627 as addressing electric self-propelled vehicle power transfer systems, expanding beyond only on-road electric vehicles.', '2026 NFPA public input for Article 627', 'advanced', TRUE);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('ee0b5755-e3b9-42ce-9df7-4a3bdf9ce195', 'ap-mod-001-electrical-theory-fundamentals', 'Electrical Theory Fundamentals', 'Explain voltage, current, resistance, power, and energy using trade language. Apply Ohm''s Law and Watt''s Law to simple series and parallel circuits. Recognize the difference between theory concepts and NEC installation rules.', 'apprentice', 'beginner', 1, TRUE, 40);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('d024fe95-d588-43cd-a807-746b280473ee', 'ap-mod-002-basic-safety-osha-and-nfpa-70e', 'Basic Safety (OSHA and NFPA 70E)', 'Identify electrical shock, arc-flash, and arc-blast hazards. Connect OSHA work-practice expectations with jobsite behavior. Explain why de-energization and verification matter before beginning work.', 'apprentice', 'beginner', 2, TRUE, 50);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('6349084a-f462-4cf3-b879-ac413857bf3a', 'ap-mod-003-introduction-to-the-nec', 'Introduction to the NEC', 'Navigate articles, parts, sections, tables, and informational notes. Differentiate enforceable rules from explanatory material. Find foundational definitions and general installation rules quickly.', 'apprentice', 'beginner', 3, TRUE, 40);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('cafa68a2-0874-4bfc-801b-6cbd5bcfb6da', 'ap-mod-004-wiring-methods-and-materials', 'Wiring Methods and Materials', 'Recognize common raceways, cable assemblies, and conductor types. Use Chapter 3 articles to identify permitted uses and support rules. Connect conductor sizing to insulation, ampacity, and environment.', 'apprentice', 'beginner', 4, TRUE, 50);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('dbe448e2-6a4f-49e0-bc5f-aec39222ba68', 'jr-mod-001-advanced-nec-navigation', 'Advanced NEC Navigation', 'Move between Chapters 1 through 4 and special rules in Chapters 5 through 7 efficiently. Use article structure to solve open-book exam questions faster. Spot when a general rule is modified by a special occupancy or equipment article.', 'journeyman', 'intermediate', 5, TRUE, 45);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('78b998ba-afa3-4247-8f34-b335c86a3404', 'jr-mod-002-branch-circuits-and-feeders', 'Branch Circuits and Feeders', 'Apply branch-circuit, feeder, and continuous-load sizing rules. Use Article 210, 215, and 220 together during load questions. Evaluate receptacle, small-appliance, and dwelling-unit circuit requirements.', 'journeyman', 'intermediate', 6, TRUE, 50);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('eea4723d-bbfe-4863-aa3c-9e8ac34193a4', 'jr-mod-003-grounding-and-bonding', 'Grounding and Bonding', 'Separate grounding functions from bonding functions. Identify service bonding jumper, equipment grounding conductor, and grounding electrode conductor paths. Use Article 250 tables and definitions correctly.', 'journeyman', 'intermediate', 7, TRUE, 60);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('8b56af98-e0fc-43e9-9472-76cf50430730', 'jr-mod-004-motors-and-controls', 'Motors and Controls', 'Locate full-load current, conductor sizing, overload, and short-circuit rules. Use motor tables instead of nameplate current where required by the NEC. Explain the difference between overload protection and short-circuit protection.', 'journeyman', 'intermediate', 8, TRUE, 60);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('cb3a3e6b-211a-4686-86d6-762fe27f1d01', 'ms-mod-001-advanced-system-design', 'Advanced System Design', 'Evaluate service, feeder, and distribution concepts at a system level. Apply demand and diversity concepts across dwelling and commercial scenarios. Integrate emerging 2026 organization changes into code-navigation habits.', 'master', 'advanced', 9, TRUE, 60);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('991ad014-10ca-4408-988c-864af282d9a3', 'ms-mod-002-complex-load-calculations', 'Complex Load Calculations', 'Perform multifamily, commercial, and mixed-use load calculations. Differentiate standard, optional, and equipment-specific methods. Translate load calculations into service and feeder conductor sizing.', 'master', 'advanced', 10, TRUE, 70);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('9fa168f1-affb-435f-947e-64f89376e314', 'ms-mod-003-hazardous-locations', 'Hazardous Locations', 'Identify Class, Division, and Zone concepts at a code-navigation level. Use Articles 500 through 516 to find occupancy-specific rules. Avoid common exam mistakes involving sealing fittings, temperature limits, and equipment suitability.', 'master', 'advanced', 11, TRUE, 70);
INSERT INTO modules (id, slug, title, description, exam_type, difficulty_level, sort_order, is_published, estimated_minutes) VALUES ('2d20bbfb-6ef2-4fcc-b2f6-4d0d923e92e5', 'ms-mod-004-code-interpretation-and-compliance', 'Code Interpretation and Compliance', 'Use scope, purpose, and hierarchy rules to resolve code questions. Recognize when jurisdictional policy or adopted amendments change the answer path. Tie technical compliance decisions to plan review, inspection, and business risk.', 'master', 'advanced', 12, TRUE, 50);
INSERT INTO module_topic_tags (module_id, topic_tag_id) VALUES ('ee0b5755-e3b9-42ce-9df7-4a3bdf9ce195', '141787d3-0567-499d-a3c4-58bd743c18b0');
