INSERT INTO module_topic_tags (module_id, topic_tag_id) VALUES ('2d20bbfb-6ef2-4fcc-b2f6-4d0d923e92e5', '9fc0454a-c601-4c29-b7c1-a1b81ebb7290');
INSERT INTO module_topic_tags (module_id, topic_tag_id) VALUES ('2d20bbfb-6ef2-4fcc-b2f6-4d0d923e92e5', '2e6283ef-a07b-4907-9dfa-02a4514416fa');
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('17f22a38-65fd-490d-a693-7959af870f49', 'ee0b5755-e3b9-42ce-9df7-4a3bdf9ce195', 'ap-les-001-voltage-current-resistance-and-ohm-s-law', 'Voltage, Current, Resistance, and Ohm''s Law', 'Electrical Theory Fundamentals', 'If you do not understand how pressure, flow, and opposition work together, later topics like voltage drop, ampacity, and troubleshooting feel random. Apprentice exams use these ideas as the foundation for many basic questions.', 'apprentice', 'beginner', 1, 20, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('99d41b80-62a0-471b-9879-4c7028a68acd', 'ee0b5755-e3b9-42ce-9df7-4a3bdf9ce195', 'ap-les-002-power-energy-and-basic-circuit-relationships', 'Power, Energy, and Basic Circuit Relationships', 'Electrical Theory Fundamentals', 'Electricians size equipment, compare loads, and think about consumption every day. Exams also use watts and watt-hours to test whether you understand the difference between how fast energy is used and how much energy is used over time.', 'apprentice', 'beginner', 2, 20, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('c167d77b-7b7b-44eb-a685-6cf54598948e', 'd024fe95-d588-43cd-a807-746b280473ee', 'ap-les-003-electrical-hazard-recognition-and-safe-work-basics', 'Electrical Hazard Recognition and Safe Work Basics', 'Basic Safety (OSHA and NFPA 70E)', 'Safety questions are not filler. They test whether you understand the real consequences of bad decisions around energized equipment, poor access, and improper installation. A calm safety mindset protects both test scores and real people.', 'apprentice', 'beginner', 1, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 'd024fe95-d588-43cd-a807-746b280473ee', 'ap-les-004-shock-paths-ppe-and-lockout-mindset', 'Shock Paths, PPE, and Lockout Mindset', 'Basic Safety (OSHA and NFPA 70E)', 'A lot of injuries happen because someone assumes equipment is off, assumes another worker already made it safe, or assumes gloves alone solve the problem. Exams test that mindset because the real job depends on it.', 'apprentice', 'beginner', 2, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('222483b9-7334-4522-bedb-2a293728377c', '6349084a-f462-4cf3-b879-ac413857bf3a', 'ap-les-005-how-the-nec-is-organized', 'How the NEC Is Organized', 'Introduction to the NEC', 'Open-book exam speed does not come from memorizing every section. It comes from knowing where a topic usually lives and how the code is organized. That skill saves time on the job too.', 'apprentice', 'beginner', 1, 20, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('2be6d8d4-ff37-4d29-a935-bca89d99ff50', '6349084a-f462-4cf3-b879-ac413857bf3a', 'ap-les-006-code-lookup-drill-article-100-and-article-110', 'Code Lookup Drill: Article 100 and Article 110', 'Introduction to the NEC', 'Many apprentice candidates know the topic but still miss the question because they searched in the wrong order. A repeatable lookup process turns open-book exams into a navigation problem instead of a panic problem.', 'apprentice', 'beginner', 2, 20, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('e7f99f77-30e4-464e-9ede-d016be784019', 'cafa68a2-0874-4bfc-801b-6cbd5bcfb6da', 'ap-les-007-raceways-cables-and-boxes', 'Raceways, Cables, and Boxes', 'Wiring Methods and Materials', 'Apprentice exams often mix material recognition with simple rule application. On the job, the wrong raceway, cable assembly, or box size can create support problems, overcrowded splices, and failed inspections before the system is even energized.', 'apprentice', 'beginner', 1, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('a634384e-cd8a-4305-acc1-7001313e16c9', 'cafa68a2-0874-4bfc-801b-6cbd5bcfb6da', 'ap-les-008-conductor-sizing-and-table-navigation', 'Conductor Sizing and Table Navigation', 'Wiring Methods and Materials', 'Wire sizing is one of the first places where new learners feel buried by tables. Exams reward students who know what the table is actually telling them and what conditions can reduce the usable ampacity.', 'apprentice', 'beginner', 2, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('40f011ac-7be9-4e37-bd7c-91607a241a3e', 'dbe448e2-6a4f-49e0-bc5f-aec39222ba68', 'jr-les-001-general-rules-vs-special-rules', 'General Rules vs Special Rules', 'Advanced NEC Navigation', 'Journeyman exams stop rewarding simple recognition alone. They often test whether you know which rule governs when two sections seem to compete. That is really a hierarchy problem.', 'journeyman', 'intermediate', 1, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('dd2810b6-f800-413a-b5d8-1dc15de2bab0', 'dbe448e2-6a4f-49e0-bc5f-aec39222ba68', 'jr-les-002-timed-code-lookup-strategies', 'Timed Code Lookup Strategies', 'Advanced NEC Navigation', 'Timed open-book exams punish wandering. The candidate who knows how to narrow the search wins back minutes that can be used on calculations and review.', 'journeyman', 'intermediate', 2, 20, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('38a5b1ac-e91d-491f-b720-75c70d567b19', '78b998ba-afa3-4247-8f34-b335c86a3404', 'jr-les-003-continuous-loads-and-overcurrent-device-sizing', 'Continuous Loads and Overcurrent Device Sizing', 'Branch Circuits and Feeders', 'This topic shows up constantly because it blends code language, arithmetic, and logic. A student may know the 125 percent rule but still miss the question by applying it to the wrong component.', 'journeyman', 'intermediate', 1, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('59716e7a-bab8-43b2-9c07-1d2cd724f02e', '78b998ba-afa3-4247-8f34-b335c86a3404', 'jr-les-004-dwelling-receptacles-and-small-appliance-circuits', 'Dwelling Receptacles and Small-Appliance Circuits', 'Branch Circuits and Feeders', 'Dwelling-unit questions are frequent because they connect everyday residential layouts to code decisions. They are also easy points for candidates who can separate required circuits from required outlet placement instead of treating Article 210 like one giant memorization problem.', 'journeyman', 'intermediate', 2, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('71144249-a131-40b6-b7ce-33ff65c69919', 'eea4723d-bbfe-4863-aa3c-9e8ac34193a4', 'jr-les-005-grounding-vs-bonding-at-services-and-feeders', 'Grounding vs Bonding at Services and Feeders', 'Grounding and Bonding', 'Grounding and bonding is one of the most misunderstood electrician exam topics. Students often know pieces of the vocabulary but cannot explain the function of each conductor or connection point.', 'journeyman', 'intermediate', 1, 30, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('0c6b6af9-e148-435c-a9ee-82726bfb398b', 'eea4723d-bbfe-4863-aa3c-9e8ac34193a4', 'jr-les-006-grounding-electrodes-and-electrode-conductors', 'Grounding Electrodes and Electrode Conductors', 'Grounding and Bonding', 'This topic appears in both direct code questions and bigger service questions. Students lose easy points when they know electrode names but do not understand the system idea behind them.', 'journeyman', 'intermediate', 2, 30, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', '8b56af98-e0fc-43e9-9472-76cf50430730', 'jr-les-007-motor-circuit-conductors-and-overload-protection', 'Motor Circuit Conductors and Overload Protection', 'Motors and Controls', 'Motor questions scare many candidates because the rules feel different from everyday branch-circuit work. The difference is intentional. Motors start, run, and overload in ways that ordinary lighting loads do not.', 'journeyman', 'intermediate', 1, 30, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('ed52a359-658b-433e-bba4-0680bf829ff9', '8b56af98-e0fc-43e9-9472-76cf50430730', 'jr-les-008-motor-branch-circuit-short-circuit-and-ground-fault-protection', 'Motor Branch-Circuit Short-Circuit and Ground-Fault Protection', 'Motors and Controls', 'Students often panic when they see a motor protective-device value that seems larger than the conductor ampacity or overload setting. The rules look unusual only until you understand the purpose of each protective layer.', 'journeyman', 'intermediate', 2, 30, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 'cb3a3e6b-211a-4686-86d6-762fe27f1d01', 'ms-les-001-service-and-feeder-design-workflow', 'Service and Feeder Design Workflow', 'Advanced System Design', 'Master-level exams reward process discipline. These questions are less about one isolated section and more about whether you can move through the design path without skipping a step.', 'master', 'advanced', 1, 35, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 'cb3a3e6b-211a-4686-86d6-762fe27f1d01', 'ms-les-002-using-tables-notes-and-exceptions-efficiently', 'Using Tables, Notes, and Exceptions Efficiently', 'Advanced System Design', 'Master exams often hide the real challenge in the small print. A student may know the main rule but still miss the problem by overlooking a table note, exception, or limitation that changes the result.', 'master', 'advanced', 2, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('fa82e6c5-799d-4610-a465-cdf06f82724b', '991ad014-10ca-4408-988c-864af282d9a3', 'ms-les-003-dwelling-optional-calculation-workflow', 'Dwelling Optional Calculation Workflow', 'Complex Load Calculations', 'Optional dwelling calculations are attractive because they can simplify service-sizing problems, but they also create mistakes when students apply the method too casually or mix it with standard-method logic.', 'master', 'advanced', 1, 35, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('e0b1e379-a058-4bf9-970c-225a755f9a07', '991ad014-10ca-4408-988c-864af282d9a3', 'ms-les-004-commercial-demand-and-feeder-sizing', 'Commercial Demand and Feeder Sizing', 'Complex Load Calculations', 'Commercial calculations combine several load types, which makes them easy to overcount or undercount. Master-level questions reward candidates who organize the load categories before they start doing arithmetic.', 'master', 'advanced', 2, 35, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('e4a8125f-68c4-4d24-b811-6de74f9aa85b', '9fa168f1-affb-435f-947e-64f89376e314', 'ms-les-005-hazardous-location-classification-fundamentals', 'Hazardous Location Classification Fundamentals', 'Hazardous Locations', 'Hazardous-location questions feel intimidating because the vocabulary is dense. But once you understand what is being classified and why, the topic becomes much more teachable and much less mysterious.', 'master', 'advanced', 1, 35, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('962e1229-3cb3-4e52-853b-e565e4aaf88a', '9fa168f1-affb-435f-947e-64f89376e314', 'ms-les-006-motors-seals-and-equipment-selection-in-classified-areas', 'Motors, Seals, and Equipment Selection in Classified Areas', 'Hazardous Locations', 'After classification, master-level questions usually shift into application. That is where many candidates lose points. They know the area is hazardous, but they cannot explain why a certain motor, enclosure, or sealing approach is or is not acceptable.', 'master', 'advanced', 2, 35, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('f1b37758-4019-4b8e-8264-ed5a2a5c798f', '2d20bbfb-6ef2-4fcc-b2f6-4d0d923e92e5', 'ms-les-007-reading-90-1-90-3-and-article-100-like-a-master', 'Reading 90.1, 90.3, and Article 100 Like a Master', 'Code Interpretation and Compliance', 'At the master level, the code is not just a list of isolated rules. It is a structured document with purpose, hierarchy, and defined language. These opening sections help you reason through hard questions instead of just hunting citations.', 'master', 'advanced', 1, 25, TRUE);
INSERT INTO lessons (id, module_id, slug, title, subtitle, summary, exam_type, difficulty_level, sort_order, estimated_minutes, is_published) VALUES ('9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', '2d20bbfb-6ef2-4fcc-b2f6-4d0d923e92e5', 'ms-les-008-when-the-nec-is-not-the-whole-answer', 'When the NEC Is Not the Whole Answer', 'Code Interpretation and Compliance', 'Master electricians are expected to think beyond a single section citation. Real projects involve code adoption, authority-having-jurisdiction decisions, listed-equipment instructions, and local processes that affect what actually gets approved and installed.', 'master', 'advanced', 2, 25, TRUE);
INSERT INTO lesson_topic_tags (lesson_id, topic_tag_id) VALUES ('17f22a38-65fd-490d-a693-7959af870f49', '141787d3-0567-499d-a3c4-58bd743c18b0');
