INSERT INTO lesson_topic_tags (lesson_id, topic_tag_id) VALUES ('9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 'f261ed2b-430d-476f-8910-605d4d116fa8');
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('65b31c7b-2df5-492d-bd83-aa1955ece60d', '17f22a38-65fd-490d-a693-7959af870f49', 1, 'paragraph', 'Learning objective', 'Explain what voltage, current, and resistance mean in plain trade language, and use Ohm''s Law to solve simple circuit questions.', 'Explain what voltage, current, and resistance mean in plain trade language, and use Ohm''s Law to solve simple circuit questions.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2dba875a-bf77-40d4-8ef2-28bc1823eac6', '17f22a38-65fd-490d-a693-7959af870f49', 2, 'paragraph', 'Why this matters', 'If you do not understand how pressure, flow, and opposition work together, later topics like voltage drop, ampacity, and troubleshooting feel random. Apprentice exams use these ideas as the foundation for many basic questions.', 'If you do not understand how pressure, flow, and opposition work together, later topics like voltage drop, ampacity, and troubleshooting feel random. Apprentice exams use these ideas as the foundation for many basic questions.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('078720f5-b41d-4983-90b6-dfce65715d1f', '17f22a38-65fd-490d-a693-7959af870f49', 3, 'paragraph', 'Core explanation', 'Voltage is electrical pressure. Current is the flow of charge. Resistance is anything that slows that flow down. Ohm''s Law ties them together with one simple relationship: voltage equals current times resistance. If you know any two values, you can solve for the third. That is why this formula shows up everywhere from classroom practice to real troubleshooting.', 'Voltage is electrical pressure. Current is the flow of charge. Resistance is anything that slows that flow down. Ohm''s Law ties them together with one simple relationship: voltage equals current times resistance. If you know any two values, you can solve for the third. That is why this formula shows up everywhere from classroom practice to real troubleshooting.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('60dfc0bb-ecf3-4cf4-92aa-fc812c1f02db', '17f22a38-65fd-490d-a693-7959af870f49', 4, 'paragraph', 'Key concepts', 'A higher voltage can push more current through the same resistance. A higher resistance reduces current when voltage stays the same. Units matter: volts for pressure, amps for current, and ohms for resistance. On exams, the trap is often not the math itself but mixing up which value you are solving for.', 'A higher voltage can push more current through the same resistance. A higher resistance reduces current when voltage stays the same. Units matter: volts for pressure, amps for current, and ohms for resistance. On exams, the trap is often not the math itself but mixing up which value you are solving for.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8c29f13c-e6e6-4e95-8ff5-38b87daf25c8', '17f22a38-65fd-490d-a693-7959af870f49', 5, 'paragraph', 'NEC / code relevance', 'The NEC is not a theory textbook, but Article 100 definitions help you read questions correctly. The code assumes you understand what current, conductors, equipment, and circuits are before you apply installation rules. Learn the physics first, then use the NEC for the installation answer.', 'The NEC is not a theory textbook, but Article 100 definitions help you read questions correctly. The code assumes you understand what current, conductors, equipment, and circuits are before you apply installation rules. Learn the physics first, then use the NEC for the installation answer.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2e85944b-e26a-465e-b080-091d8b07debd', '17f22a38-65fd-490d-a693-7959af870f49', 6, 'paragraph', 'Practical example', 'A 120-volt circuit feeds a load with 12 ohms of resistance. Current equals 120 divided by 12, so the answer is 10 amps. If the resistance drops to 6 ohms and voltage stays the same, current rises to 20 amps. That simple change shows why faults and low-resistance paths can become dangerous fast.', 'A 120-volt circuit feeds a load with 12 ohms of resistance. Current equals 120 divided by 12, so the answer is 10 amps. If the resistance drops to 6 ohms and voltage stays the same, current rises to 20 amps. That simple change shows why faults and low-resistance paths can become dangerous fast.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('abb6069f-a4fc-4404-bfb0-254ef8e89ef8', '17f22a38-65fd-490d-a693-7959af870f49', 7, 'paragraph', 'Common mistakes', 'Students often treat voltage and current like they are the same thing. They are not. Another common mistake is solving V = I x R backward or forgetting the units. On a timed test, write the formula first so you do not substitute values into the wrong spot.', 'Students often treat voltage and current like they are the same thing. They are not. Another common mistake is solving V = I x R backward or forgetting the units. On a timed test, write the formula first so you do not substitute values into the wrong spot.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a46eed6a-3d67-49b8-90a2-04f989677fae', '17f22a38-65fd-490d-a693-7959af870f49', 8, 'paragraph', 'Exam insight', 'Expect straightforward calculation questions, missing-value questions, and word problems that describe one value as pressure or flow. If the problem looks long, slow down and identify the two known values before you touch the calculator.', 'Expect straightforward calculation questions, missing-value questions, and word problems that describe one value as pressure or flow. If the problem looks long, slow down and identify the two known values before you touch the calculator.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2098c4e8-b4c0-47be-861f-3338971e06e8', '17f22a38-65fd-490d-a693-7959af870f49', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2f14f5d0-cdca-4fd6-a8c6-a22479adbf42', '17f22a38-65fd-490d-a693-7959af870f49', 10, 'bullet', NULL, 'Voltage is the push, current is the flow, and resistance opposes the flow.', 'Voltage is the push, current is the flow, and resistance opposes the flow.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('07b8aef3-379f-48ff-b883-efb3b2387e97', '17f22a38-65fd-490d-a693-7959af870f49', 11, 'bullet', NULL, 'Ohm''s Law is V = I x R.', 'Ohm''s Law is V = I x R.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('651b0d57-a25e-4cf7-94b0-a68c764049e1', '17f22a38-65fd-490d-a693-7959af870f49', 12, 'bullet', NULL, 'If you know any two values, you can solve for the third.', 'If you know any two values, you can solve for the third.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fc10b2ce-6b86-40a7-aa79-d20da15b5192', '17f22a38-65fd-490d-a693-7959af870f49', 13, 'bullet', NULL, 'Most beginner mistakes come from mixing up units or solving for the wrong value.', 'Most beginner mistakes come from mixing up units or solving for the wrong value.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('538d7d68-88c6-4b31-96e1-02c48218cc10', '17f22a38-65fd-490d-a693-7959af870f49', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fb88f162-1192-451b-8fb4-9dcca5668040', '17f22a38-65fd-490d-a693-7959af870f49', 15, 'callout', 'Question 1', 'A circuit has 240 volts and 20 ohms of resistance. What is the current?', 'A circuit has 240 volts and 20 ohms of resistance. What is the current?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('09c5e63e-edcf-4ec3-a97b-40be7e8b552b', '17f22a38-65fd-490d-a693-7959af870f49', 16, 'callout', 'Question 2', 'If current is 8 amps and resistance is 15 ohms, what is the voltage?', 'If current is 8 amps and resistance is 15 ohms, what is the voltage?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('94fde8cd-af60-4a34-bfa9-45712a2df39b', '17f22a38-65fd-490d-a693-7959af870f49', 17, 'callout', 'Question 3', 'Why does current increase when resistance drops and voltage stays the same?', 'Why does current increase when resistance drops and voltage stays the same?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1d09206f-60f4-4acd-8be5-650044266d71', '99d41b80-62a0-471b-9879-4c7028a68acd', 1, 'paragraph', 'Learning objective', 'Differentiate power from energy and solve basic watt and watt-hour questions using simple circuit relationships.', 'Differentiate power from energy and solve basic watt and watt-hour questions using simple circuit relationships.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('13c5df73-db3a-4b11-9da5-e9a203c35faa', '99d41b80-62a0-471b-9879-4c7028a68acd', 2, 'paragraph', 'Why this matters', 'Electricians size equipment, compare loads, and think about consumption every day. Exams also use watts and watt-hours to test whether you understand the difference between how fast energy is used and how much energy is used over time.', 'Electricians size equipment, compare loads, and think about consumption every day. Exams also use watts and watt-hours to test whether you understand the difference between how fast energy is used and how much energy is used over time.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ce280c54-d738-48cb-898a-57f95a0e7565', '99d41b80-62a0-471b-9879-4c7028a68acd', 3, 'paragraph', 'Core explanation', 'Power is the rate at which electrical work is being done. The basic formula is watts equals volts times amps. Energy adds time to that idea. If a piece of equipment uses 1,200 watts for one hour, it uses 1,200 watt-hours, or 1.2 kilowatt-hours. Power answers how fast. Energy answers how much over time.', 'Power is the rate at which electrical work is being done. The basic formula is watts equals volts times amps. Energy adds time to that idea. If a piece of equipment uses 1,200 watts for one hour, it uses 1,200 watt-hours, or 1.2 kilowatt-hours. Power answers how fast. Energy answers how much over time.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6a77568e-c735-4877-8f59-fbfacba76700', '99d41b80-62a0-471b-9879-4c7028a68acd', 4, 'paragraph', 'Key concepts', 'A load can have high power for a short time or lower power for a long time. Both affect energy use differently. You can also rewrite power formulas with Ohm''s Law, such as P = I squared x R and P = V squared divided by R. On beginner exams, though, the most common form is still P = V x I.', 'A load can have high power for a short time or lower power for a long time. Both affect energy use differently. You can also rewrite power formulas with Ohm''s Law, such as P = I squared x R and P = V squared divided by R. On beginner exams, though, the most common form is still P = V x I.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('af696930-8ac4-409a-86a6-7fa76db146c6', '99d41b80-62a0-471b-9879-4c7028a68acd', 5, 'paragraph', 'NEC / code relevance', 'The NEC uses load calculations built from volt-amperes, watts, and demand concepts. Even when the code question is not written as a physics problem, you still need to understand how power relates to current draw and equipment demand.', 'The NEC uses load calculations built from volt-amperes, watts, and demand concepts. Even when the code question is not written as a physics problem, you still need to understand how power relates to current draw and equipment demand.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('31ecb7cf-6d86-4280-a25f-0e21dddbf3ec', '99d41b80-62a0-471b-9879-4c7028a68acd', 6, 'paragraph', 'Practical example', 'A 120-volt appliance draws 10 amps. Power is 120 times 10, so the appliance uses 1,200 watts. If it runs for 3 hours, it uses 3,600 watt-hours, or 3.6 kilowatt-hours. That same thinking helps when comparing branch-circuit load to breaker size and daily energy use.', 'A 120-volt appliance draws 10 amps. Power is 120 times 10, so the appliance uses 1,200 watts. If it runs for 3 hours, it uses 3,600 watt-hours, or 3.6 kilowatt-hours. That same thinking helps when comparing branch-circuit load to breaker size and daily energy use.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7a6c660d-3d28-423f-93fc-c392fa138d1d', '99d41b80-62a0-471b-9879-4c7028a68acd', 7, 'paragraph', 'Common mistakes', 'One common mistake is calling watts and watt-hours the same thing. Another is forgetting to convert watt-hours to kilowatt-hours by dividing by 1,000. On tests, watch for answer choices that are numerically close but use the wrong unit.', 'One common mistake is calling watts and watt-hours the same thing. Another is forgetting to convert watt-hours to kilowatt-hours by dividing by 1,000. On tests, watch for answer choices that are numerically close but use the wrong unit.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f967c3b1-c49b-4536-93b4-7be5feba663d', '99d41b80-62a0-471b-9879-4c7028a68acd', 8, 'paragraph', 'Exam insight', 'Power questions are often short and direct, but they may be mixed into load, motor, or service-sizing problems later. Get comfortable changing between volts, amps, watts, and time without overthinking it.', 'Power questions are often short and direct, but they may be mixed into load, motor, or service-sizing problems later. Get comfortable changing between volts, amps, watts, and time without overthinking it.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dbfaa692-dfc2-43bc-9c10-fdde389399cc', '99d41b80-62a0-471b-9879-4c7028a68acd', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('572e7550-41d2-48ce-bf9d-074d9e7b6fe3', '99d41b80-62a0-471b-9879-4c7028a68acd', 10, 'bullet', NULL, 'Power tells you the rate of use. Energy tells you use over time.', 'Power tells you the rate of use. Energy tells you use over time.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5b528b13-27ca-42ba-8b0f-337850ba67fd', '99d41b80-62a0-471b-9879-4c7028a68acd', 11, 'bullet', NULL, 'The basic power formula is P = V x I.', 'The basic power formula is P = V x I.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a9f6d8fb-80f6-474a-af1b-cfc14e836f43', '99d41b80-62a0-471b-9879-4c7028a68acd', 12, 'bullet', NULL, 'Kilowatt-hours are watt-hours divided by 1,000.', 'Kilowatt-hours are watt-hours divided by 1,000.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8ec31e99-4390-4697-b9b3-a31f06cda6f9', '99d41b80-62a0-471b-9879-4c7028a68acd', 13, 'bullet', NULL, 'The unit matters as much as the number.', 'The unit matters as much as the number.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d73a8508-35ac-4c66-a97f-1edc7efa9572', '99d41b80-62a0-471b-9879-4c7028a68acd', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9e474a5c-fe0f-42eb-a48d-a30113b8c4d2', '99d41b80-62a0-471b-9879-4c7028a68acd', 15, 'callout', 'Question 1', 'A 240-volt water heater draws 18 amps. How many watts does it use?', 'A 240-volt water heater draws 18 amps. How many watts does it use?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6f9a1165-f8d4-4dfc-b452-4bbda2bd68aa', '99d41b80-62a0-471b-9879-4c7028a68acd', 16, 'callout', 'Question 2', 'If a 1,500-watt heater runs for 2 hours, how many kilowatt-hours does it use?', 'If a 1,500-watt heater runs for 2 hours, how many kilowatt-hours does it use?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e4a1dad4-3303-4c9c-ba26-ef338091985e', '99d41b80-62a0-471b-9879-4c7028a68acd', 17, 'callout', 'Question 3', 'Why is a watt-hour not the same thing as a watt?', 'Why is a watt-hour not the same thing as a watt?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4c3de6d9-d08b-4a9c-be22-a9717409da93', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 1, 'paragraph', 'Learning objective', 'Identify common electrical hazards and explain the basic safe-work habits that reduce shock, burn, and arc-related risk.', 'Identify common electrical hazards and explain the basic safe-work habits that reduce shock, burn, and arc-related risk.', '{"necReferences":["110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c8d7539f-6578-47d2-bf97-2dde9b45a31c', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 2, 'paragraph', 'Why this matters', 'Safety questions are not filler. They test whether you understand the real consequences of bad decisions around energized equipment, poor access, and improper installation. A calm safety mindset protects both test scores and real people.', 'Safety questions are not filler. They test whether you understand the real consequences of bad decisions around energized equipment, poor access, and improper installation. A calm safety mindset protects both test scores and real people.', '{"necReferences":["110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('02f8316c-681c-4ae7-b9a3-7dc00a150aa8', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 3, 'paragraph', 'Core explanation', 'Electrical hazards usually show up as shock, burn, blast pressure, or fire risk. Shock happens when current travels through the body. Arc-flash hazards involve intense heat and light from an electrical fault. Good safety habits start with planning the task, controlling exposure, and reducing the chance of accidental contact or fault energy.', 'Electrical hazards usually show up as shock, burn, blast pressure, or fire risk. Shock happens when current travels through the body. Arc-flash hazards involve intense heat and light from an electrical fault. Good safety habits start with planning the task, controlling exposure, and reducing the chance of accidental contact or fault energy.', '{"necReferences":["110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5aecfa28-e474-4958-aac2-a18083da1512', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 4, 'paragraph', 'Key concepts', 'Hazard recognition means looking for energized parts, damaged insulation, wet conditions, poor housekeeping, and blocked access. Safe work basics include de-energizing when possible, using the right tools, keeping required working space clear, and following equipment instructions. Safety is not one step. It is a chain of correct decisions.', 'Hazard recognition means looking for energized parts, damaged insulation, wet conditions, poor housekeeping, and blocked access. Safe work basics include de-energizing when possible, using the right tools, keeping required working space clear, and following equipment instructions. Safety is not one step. It is a chain of correct decisions.', '{"necReferences":["110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0fbb918f-f410-4eab-bb94-46ba86c823c4', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 5, 'paragraph', 'NEC / code relevance', 'NEC 110.26 supports safe access and working space around equipment. NEC 110.3(B) matters because listed equipment has to be installed and used according to its instructions. Many unsafe conditions start when installers ignore the product listing or crowd the workspace around equipment.', 'NEC 110.26 supports safe access and working space around equipment. NEC 110.3(B) matters because listed equipment has to be installed and used according to its instructions. Many unsafe conditions start when installers ignore the product listing or crowd the workspace around equipment.', '{"necReferences":["110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('53f66443-1e92-427b-842f-2078b3e1aee7', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 6, 'paragraph', 'Practical example', 'A worker opens a panel in a tight storage closet with boxes stacked in front of it. Even before touching a conductor, the setup is unsafe because required access and working space are compromised. Good hazard recognition means stopping before the task begins, not after something goes wrong.', 'A worker opens a panel in a tight storage closet with boxes stacked in front of it. Even before touching a conductor, the setup is unsafe because required access and working space are compromised. Good hazard recognition means stopping before the task begins, not after something goes wrong.', '{"necReferences":["110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1e1f449f-4132-4f82-bbd4-e022077ed60e', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 7, 'paragraph', 'Common mistakes', 'New learners sometimes think safety only means wearing gloves. PPE matters, but it does not replace planning, de-energizing, verifying, and keeping clear working space. Another mistake is treating near misses like proof that a shortcut is acceptable.', 'New learners sometimes think safety only means wearing gloves. PPE matters, but it does not replace planning, de-energizing, verifying, and keeping clear working space. Another mistake is treating near misses like proof that a shortcut is acceptable.', '{"necReferences":["110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2cfcd81a-abfa-4af2-a507-10aeafa89d2b', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 8, 'paragraph', 'Exam insight', 'Expect questions that ask which condition is unsafe, what step should happen first, or why access and labeling matter. Choose the answer that reduces exposure before the work starts, not the answer that reacts after the hazard is already in front of you.', 'Expect questions that ask which condition is unsafe, what step should happen first, or why access and labeling matter. Choose the answer that reduces exposure before the work starts, not the answer that reacts after the hazard is already in front of you.', '{"necReferences":["110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c5570563-6705-4810-8aed-af4bfe9ff4c4', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f34622e1-648f-4182-9a2e-33e547517eae', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 10, 'bullet', NULL, 'Electrical hazards include shock, burns, arc-flash, blast pressure, and fire risk.', 'Electrical hazards include shock, burns, arc-flash, blast pressure, and fire risk.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('42671c2e-b11a-4b1f-9e20-73d7a837f31a', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 11, 'bullet', NULL, 'Safe work starts with planning and hazard recognition.', 'Safe work starts with planning and hazard recognition.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2df24c49-fed8-469a-a22f-34d3ed6378c8', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 12, 'bullet', NULL, 'Working space and listed-equipment instructions are safety issues, not paperwork issues.', 'Working space and listed-equipment instructions are safety issues, not paperwork issues.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a5dc753f-e5cc-4f0a-ac81-2c8d002b4607', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 13, 'bullet', NULL, 'PPE helps, but it does not replace de-energizing and verification.', 'PPE helps, but it does not replace de-energizing and verification.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b31ca5d6-4805-4684-8bd7-2f198a513e05', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('06279578-ad57-4f72-8c04-83e083018aec', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 15, 'callout', 'Question 1', 'Why is blocked panel access a safety problem even before work begins?', 'Why is blocked panel access a safety problem even before work begins?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bb3e67ad-8bc0-4dfe-8bc7-0c312799277c', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 16, 'callout', 'Question 2', 'What is the difference between a shock hazard and an arc-flash hazard?', 'What is the difference between a shock hazard and an arc-flash hazard?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1e00b9ef-f26f-4949-b022-7e14d38e219f', 'c167d77b-7b7b-44eb-a685-6cf54598948e', 17, 'callout', 'Question 3', 'Which is the safer first move: grab PPE and continue, or stop and correct the unsafe setup?', 'Which is the safer first move: grab PPE and continue, or stop and correct the unsafe setup?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c5b87a8d-9ad9-4b66-8605-d40579c35c2d', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 1, 'paragraph', 'Learning objective', 'Explain how current travels through the body, what PPE can and cannot do, and why lockout-style thinking matters before work begins.', 'Explain how current travels through the body, what PPE can and cannot do, and why lockout-style thinking matters before work begins.', '{"necReferences":["110.4","110.27"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1c5fac68-dffb-4fea-b965-7d11c45a7ec1', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 2, 'paragraph', 'Why this matters', 'A lot of injuries happen because someone assumes equipment is off, assumes another worker already made it safe, or assumes gloves alone solve the problem. Exams test that mindset because the real job depends on it.', 'A lot of injuries happen because someone assumes equipment is off, assumes another worker already made it safe, or assumes gloves alone solve the problem. Exams test that mindset because the real job depends on it.', '{"necReferences":["110.27"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('840eaa85-56b2-42b0-ae43-702625b9cc88', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 3, 'paragraph', 'Core explanation', 'Current harms the body when it finds a path through tissue. Hand-to-hand and hand-to-foot paths are especially dangerous because they can cross the chest. PPE reduces exposure, but it does not make energized work harmless. Lockout-style thinking means identifying the source, isolating it, preventing unexpected re-energization, and verifying the condition before touching conductors or equipment.', 'Current harms the body when it finds a path through tissue. Hand-to-hand and hand-to-foot paths are especially dangerous because they can cross the chest. PPE reduces exposure, but it does not make energized work harmless. Lockout-style thinking means identifying the source, isolating it, preventing unexpected re-energization, and verifying the condition before touching conductors or equipment.', '{"necReferences":["110.27"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c74cabf1-91ac-4f57-9bf2-49ccbaabb424', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 4, 'paragraph', 'Key concepts', 'Shock severity depends on current, path, time, and conditions such as moisture. PPE is a layer, not permission to be careless. Guarding live parts matters because accidental contact is one of the easiest ways to turn a routine task into an emergency. Safe workers assume nothing until they verify it.', 'Shock severity depends on current, path, time, and conditions such as moisture. PPE is a layer, not permission to be careless. Guarding live parts matters because accidental contact is one of the easiest ways to turn a routine task into an emergency. Safe workers assume nothing until they verify it.', '{"necReferences":["110.4","110.27"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1d504a6f-95a6-41f5-a30c-e7efe767b128', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 5, 'paragraph', 'NEC / code relevance', 'NEC 110.27 requires live parts to be guarded against accidental contact. NEC 110.4 reminds you that voltage level affects how equipment is applied and protected. The NEC does not replace lockout procedures, but it supports the same idea: control exposure to energized parts.', 'NEC 110.27 requires live parts to be guarded against accidental contact. NEC 110.4 reminds you that voltage level affects how equipment is applied and protected. The NEC does not replace lockout procedures, but it supports the same idea: control exposure to energized parts.', '{"necReferences":["110.4","110.27"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f442ff16-b954-4769-9bf9-62bd73e98b3a', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 6, 'paragraph', 'Practical example', 'Imagine a disconnect is switched off, but no one verifies absence of voltage at the load side. A mislabeled source or backfeed can still leave dangerous voltage present. The correct habit is not to trust position alone. It is to isolate, lock or secure when required, and verify.', 'Imagine a disconnect is switched off, but no one verifies absence of voltage at the load side. A mislabeled source or backfeed can still leave dangerous voltage present. The correct habit is not to trust position alone. It is to isolate, lock or secure when required, and verify.', '{"necReferences":["110.27"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b4abd6e3-ae85-40e5-90dc-56a76bdcdcd3', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 7, 'paragraph', 'Common mistakes', 'The biggest mistake is confusing turned off with electrically safe. Another is believing PPE makes direct contact acceptable. Learners also forget that metal ladders, wet hands, and cramped body position can increase the danger of a shock path.', 'The biggest mistake is confusing turned off with electrically safe. Another is believing PPE makes direct contact acceptable. Learners also forget that metal ladders, wet hands, and cramped body position can increase the danger of a shock path.', '{"necReferences":["110.27"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('485a8a52-5307-47e8-b14b-a9c75b05e599', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 8, 'paragraph', 'Exam insight', 'On safety questions, the best answer usually includes isolation and verification. If two answers both sound reasonable, choose the one that removes uncertainty instead of the one that simply hopes the circuit is dead.', 'On safety questions, the best answer usually includes isolation and verification. If two answers both sound reasonable, choose the one that removes uncertainty instead of the one that simply hopes the circuit is dead.', '{"necReferences":["110.4","110.27"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c90981ca-f1bc-4b5c-9154-a62fe0cc7e82', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4fdcd290-22d7-4084-a4aa-c601102f77b2', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 10, 'bullet', NULL, 'Current must have a path, and the body can become that path.', 'Current must have a path, and the body can become that path.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d919b2b1-fac5-4420-81ca-c5085fc96ac2', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 11, 'bullet', NULL, 'PPE reduces risk but does not erase it.', 'PPE reduces risk but does not erase it.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2ce47184-7eb0-4fad-90e8-878b29517f4a', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 12, 'bullet', NULL, 'Lockout-style thinking means isolate, secure, and verify before touching.', 'Lockout-style thinking means isolate, secure, and verify before touching.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8b96ed81-035a-4ab5-8d69-d2d1ef4ec17e', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 13, 'bullet', NULL, 'Never assume equipment is safe just because a switch or disconnect is open.', 'Never assume equipment is safe just because a switch or disconnect is open.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6461757d-ade6-4e1f-b101-b8879281797a', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9b677f7a-92af-4466-aae4-e918e2f1d637', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 15, 'callout', 'Question 1', 'Why is verification more reliable than trusting a disconnect handle position?', 'Why is verification more reliable than trusting a disconnect handle position?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('06a71273-5466-4f95-9ec0-71446d4c98bf', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 16, 'callout', 'Question 2', 'What body current path is especially dangerous and why?', 'What body current path is especially dangerous and why?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7c950328-7290-47a3-a019-e4768086dd6c', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 17, 'callout', 'Question 3', 'What is one major limit of PPE in electrical work?', 'What is one major limit of PPE in electrical work?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1af16105-0525-4eab-a1fa-fe37434b3a2e', '222483b9-7334-4522-bedb-2a293728377c', 1, 'paragraph', 'Learning objective', 'Describe how the NEC is arranged so you can move through chapters, articles, parts, and definitions without getting lost.', 'Describe how the NEC is arranged so you can move through chapters, articles, parts, and definitions without getting lost.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8f2f1eb6-7d31-4613-a524-2a30d250013b', '222483b9-7334-4522-bedb-2a293728377c', 2, 'paragraph', 'Why this matters', 'Open-book exam speed does not come from memorizing every section. It comes from knowing where a topic usually lives and how the code is organized. That skill saves time on the job too.', 'Open-book exam speed does not come from memorizing every section. It comes from knowing where a topic usually lives and how the code is organized. That skill saves time on the job too.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('29d1a577-89ea-4fed-a73c-493d2fcb8fa5', '222483b9-7334-4522-bedb-2a293728377c', 3, 'paragraph', 'Core explanation', 'The NEC is organized by chapters, then articles, then sections and subsections. Chapter 1 covers general rules. Chapters 2 through 4 cover wiring and equipment. Chapters 5 through 7 can modify or add special rules. Article 100 holds definitions. Informational notes can help understanding, but they are not the same as enforceable rules.', 'The NEC is organized by chapters, then articles, then sections and subsections. Chapter 1 covers general rules. Chapters 2 through 4 cover wiring and equipment. Chapters 5 through 7 can modify or add special rules. Article 100 holds definitions. Informational notes can help understanding, but they are not the same as enforceable rules.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('65720862-c125-47b1-9c68-c27cf1eac38f', '222483b9-7334-4522-bedb-2a293728377c', 4, 'paragraph', 'Key concepts', 'Read the article title first because it tells you the subject. Read the section number carefully because small number changes can mean a completely different rule. Learn the difference between an article, a part, a table, an exception, and an informational note. Code users lose time when they skim structure instead of reading it.', 'Read the article title first because it tells you the subject. Read the section number carefully because small number changes can mean a completely different rule. Learn the difference between an article, a part, a table, an exception, and an informational note. Code users lose time when they skim structure instead of reading it.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8d610df9-103e-4126-a977-ed25d5589ffe', '222483b9-7334-4522-bedb-2a293728377c', 5, 'paragraph', 'NEC / code relevance', 'NEC 90.1 explains the practical purpose of the code. NEC 90.3 explains how the chapters interact. Article 100 is critical because defined terms control how later rules are read. If you ignore the structure, you often end up in the wrong answer path.', 'NEC 90.1 explains the practical purpose of the code. NEC 90.3 explains how the chapters interact. Article 100 is critical because defined terms control how later rules are read. If you ignore the structure, you often end up in the wrong answer path.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('52b8de2c-a1e3-44e6-bbc7-448693254b2c', '222483b9-7334-4522-bedb-2a293728377c', 6, 'paragraph', 'Practical example', 'A question asks about a required disconnect location. A strong code user first identifies the equipment type, then goes to the relevant article, then checks whether a special occupancy article changes the general rule. That is much faster than flipping pages at random.', 'A question asks about a required disconnect location. A strong code user first identifies the equipment type, then goes to the relevant article, then checks whether a special occupancy article changes the general rule. That is much faster than flipping pages at random.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f0ff5dd3-36e0-4419-96a5-2fcd41563fbd', '222483b9-7334-4522-bedb-2a293728377c', 7, 'paragraph', 'Common mistakes', 'One common mistake is treating informational notes like direct requirements. Another is skipping definitions and jumping straight to an installation rule. Students also forget that special chapters can override earlier general rules.', 'One common mistake is treating informational notes like direct requirements. Another is skipping definitions and jumping straight to an installation rule. Students also forget that special chapters can override earlier general rules.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7d52c60b-40be-4042-8a41-1b8dcb01c8b0', '222483b9-7334-4522-bedb-2a293728377c', 8, 'paragraph', 'Exam insight', 'Expect simple structure questions early and hidden structure questions later. A problem may look like a branch-circuit question but actually turn on a definition or a special rule in another chapter.', 'Expect simple structure questions early and hidden structure questions later. A problem may look like a branch-circuit question but actually turn on a definition or a special rule in another chapter.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9a891082-3989-4a9b-a806-fbe1bd11ee51', '222483b9-7334-4522-bedb-2a293728377c', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8029d21a-db39-48d4-bd87-70c322aadc90', '222483b9-7334-4522-bedb-2a293728377c', 10, 'bullet', NULL, 'The NEC is organized by chapters, articles, sections, and subsections.', 'The NEC is organized by chapters, articles, sections, and subsections.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('48010094-589d-44a9-9237-9cfd52ca188d', '222483b9-7334-4522-bedb-2a293728377c', 11, 'bullet', NULL, 'Article 100 is the definition hub for the code.', 'Article 100 is the definition hub for the code.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4a15b861-d359-4900-a3fa-c3c0f0a57867', '222483b9-7334-4522-bedb-2a293728377c', 12, 'bullet', NULL, 'Special chapters can modify general rules.', 'Special chapters can modify general rules.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('764a1338-0dac-411d-ab52-4b6f65290e7c', '222483b9-7334-4522-bedb-2a293728377c', 13, 'bullet', NULL, 'Informational notes help understanding but are not the same as enforceable text.', 'Informational notes help understanding but are not the same as enforceable text.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a217f85c-b444-4202-a73a-d9ee3ffee2b3', '222483b9-7334-4522-bedb-2a293728377c', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('657a169e-c8a1-406f-b5d4-e369c637c56e', '222483b9-7334-4522-bedb-2a293728377c', 15, 'callout', 'Question 1', 'What is the first place to check when a code question depends on a defined term?', 'What is the first place to check when a code question depends on a defined term?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('046eb964-36fc-498c-aab8-1f70e1e0f41c', '222483b9-7334-4522-bedb-2a293728377c', 16, 'callout', 'Question 2', 'Why does NEC 90.3 matter during open-book exams?', 'Why does NEC 90.3 matter during open-book exams?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e0aa7b46-4140-4e72-af8b-a461dd9279e9', '222483b9-7334-4522-bedb-2a293728377c', 17, 'callout', 'Question 3', 'What is the difference between an enforceable rule and an informational note?', 'What is the difference between an enforceable rule and an informational note?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('55d638a1-313a-4f5f-8de9-d5ef26833f0a', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 1, 'paragraph', 'Learning objective', 'Use a repeatable code-lookup process that starts with definitions, moves to the governing rule, and then checks general installation requirements.', 'Use a repeatable code-lookup process that starts with definitions, moves to the governing rule, and then checks general installation requirements.', '{"necReferences":["Article 100","110.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('89bf33d9-e62b-41cf-968a-22e9113b2f89', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 2, 'paragraph', 'Why this matters', 'Many apprentice candidates know the topic but still miss the question because they searched in the wrong order. A repeatable lookup process turns open-book exams into a navigation problem instead of a panic problem.', 'Many apprentice candidates know the topic but still miss the question because they searched in the wrong order. A repeatable lookup process turns open-book exams into a navigation problem instead of a panic problem.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('97b83d48-0120-4473-99bf-521e4e74b2b3', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 3, 'paragraph', 'Core explanation', 'Start by asking what the question is really about. If the answer depends on the meaning of a term, go to Article 100 first. Then move to the article that governs the installation itself. After that, check whether Chapter 1 or another general requirement article adds conditions about approval, listing, access, guarding, or workspace. This order keeps your search tight and logical.', 'Start by asking what the question is really about. If the answer depends on the meaning of a term, go to Article 100 first. Then move to the article that governs the installation itself. After that, check whether Chapter 1 or another general requirement article adds conditions about approval, listing, access, guarding, or workspace. This order keeps your search tight and logical.', '{"necReferences":["90.3","Article 100","110.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('44f17988-9077-428a-9f53-bf061c91c940', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 4, 'paragraph', 'Key concepts', 'Definitions tell you what the code means by a word. The rule article tells you what must be done. General requirements often tell you how the installation must be applied, approved, or accessed. Strong code users move in that order instead of flipping randomly between chapters.', 'Definitions tell you what the code means by a word. The rule article tells you what must be done. General requirements often tell you how the installation must be applied, approved, or accessed. Strong code users move in that order instead of flipping randomly between chapters.', '{"necReferences":["Article 100","110.1","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d25c043a-9915-4c67-b9a1-d089e3a447a8', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 5, 'paragraph', 'NEC / code relevance', 'Article 100 is the first stop for defined terms. NEC 110.1 and related sections matter because many installation questions also depend on listing, workmanship, guarding, or workspace. NEC 90.3 reminds you to notice whether a special rule changes the general path.', 'Article 100 is the first stop for defined terms. NEC 110.1 and related sections matter because many installation questions also depend on listing, workmanship, guarding, or workspace. NEC 90.3 reminds you to notice whether a special rule changes the general path.', '{"necReferences":["90.3","Article 100","110.1","110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('99fd27fe-6998-4ab6-8dff-4338fec590d6', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 6, 'paragraph', 'Practical example', 'Suppose a question uses the term readily accessible and asks about equipment placement. First confirm the term in Article 100. Next find the installation article for the equipment involved. Then check Article 110 for access, guarding, and workspace issues that may affect the final answer.', 'Suppose a question uses the term readily accessible and asks about equipment placement. First confirm the term in Article 100. Next find the installation article for the equipment involved. Then check Article 110 for access, guarding, and workspace issues that may affect the final answer.', '{"necReferences":["Article 100","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('87835229-c286-46b9-ac58-d630d33d7979', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 7, 'paragraph', 'Common mistakes', 'The most common mistake is starting with a guess instead of a term. Another is finding a promising rule and stopping too soon without checking for a general requirement or special exception. Students also waste time by not reading article titles carefully.', 'The most common mistake is starting with a guess instead of a term. Another is finding a promising rule and stopping too soon without checking for a general requirement or special exception. Students also waste time by not reading article titles carefully.', '{"necReferences":["90.3","110.3(B)","110.26"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('26e59a9d-e154-4827-9db4-a295eea2dcdc', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 8, 'paragraph', 'Exam insight', 'This lesson is really about speed and accuracy together. When answer choices are close, the student who checked the term first usually beats the student who guessed from memory.', 'This lesson is really about speed and accuracy together. When answer choices are close, the student who checked the term first usually beats the student who guessed from memory.', '{"necReferences":["Article 100","110.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3e11aef0-54c4-4c68-861f-797b8ce8a30b', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2b6b831d-2dc5-4a43-b953-c0212eb3a483', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 10, 'bullet', NULL, 'Definitions first, governing rule second, general requirements third.', 'Definitions first, governing rule second, general requirements third.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4870a81b-48f9-40b8-8b3d-efb0d9f8c1c0', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 11, 'bullet', NULL, 'A repeatable search order is faster than flipping pages randomly.', 'A repeatable search order is faster than flipping pages randomly.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b6618128-f0a7-417e-991b-6a65f7d20113', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 12, 'bullet', NULL, 'Article 110 often adds installation conditions that matter to the final answer.', 'Article 110 often adds installation conditions that matter to the final answer.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5e247eab-53be-4330-b6e0-f082181e6472', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 13, 'bullet', NULL, 'Careful code navigation reduces both time loss and misread questions.', 'Careful code navigation reduces both time loss and misread questions.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2b1b9ed8-1b86-4efe-8d86-c79abea47be6', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8c2b3873-a358-4906-af62-aac3e360be02', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 15, 'callout', 'Question 1', 'If a question depends on the meaning of readily accessible, where should you start?', 'If a question depends on the meaning of readily accessible, where should you start?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('839dea35-3fbb-4716-bc88-43f2783ab34b', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 16, 'callout', 'Question 2', 'After you find the installation article, what general article often deserves a quick check?', 'After you find the installation article, what general article often deserves a quick check?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('14242c30-a340-43b1-85af-e0d0f8c654a6', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 17, 'callout', 'Question 3', 'Why is a repeatable lookup process better than searching from memory alone?', 'Why is a repeatable lookup process better than searching from memory alone?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('90fb0400-acff-4447-a0ae-a789a03ceb96', 'e7f99f77-30e4-464e-9ede-d016be784019', 1, 'paragraph', 'Learning objective', 'Recognize common wiring methods and box-related rules so you can match materials to the installation and avoid basic support and fill mistakes.', 'Recognize common wiring methods and box-related rules so you can match materials to the installation and avoid basic support and fill mistakes.', '{"necReferences":["300.11","314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('70d7b65a-acab-4a1a-8158-af9477ba0b66', 'e7f99f77-30e4-464e-9ede-d016be784019', 2, 'paragraph', 'Why this matters', 'Apprentice exams often mix material recognition with simple rule application. On the job, the wrong raceway, cable assembly, or box size can create support problems, overcrowded splices, and failed inspections before the system is even energized.', 'Apprentice exams often mix material recognition with simple rule application. On the job, the wrong raceway, cable assembly, or box size can create support problems, overcrowded splices, and failed inspections before the system is even energized.', '{"necReferences":["300.11","314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('767b6894-6831-41b0-9459-387b9906e292', 'e7f99f77-30e4-464e-9ede-d016be784019', 3, 'paragraph', 'Core explanation', 'Raceways such as EMT, PVC, and rigid conduit protect conductors and give you a defined wiring path. Cable assemblies such as NM-B and MC package conductors inside one listed product. Boxes enclose splices, devices, and terminations. The right choice depends on the location, the kind of protection needed, how the wiring will be supported, and how much conductor volume the box must handle.', 'Raceways such as EMT, PVC, and rigid conduit protect conductors and give you a defined wiring path. Cable assemblies such as NM-B and MC package conductors inside one listed product. Boxes enclose splices, devices, and terminations. The right choice depends on the location, the kind of protection needed, how the wiring will be supported, and how much conductor volume the box must handle.', '{"necReferences":["300.11","314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('40c5faff-ce42-420a-bcb3-210328466f64', 'e7f99f77-30e4-464e-9ede-d016be784019', 4, 'paragraph', 'Key concepts', 'Do not treat all wiring methods as interchangeable. Some methods are better for exposed work, some for concealed work, and some for wet, damp, or corrosive conditions. Box fill is also more than physical fit. Each insulated conductor counts, all equipment grounds together count as one volume allowance, and devices or internal clamps can add more volume to the calculation.', 'Do not treat all wiring methods as interchangeable. Some methods are better for exposed work, some for concealed work, and some for wet, damp, or corrosive conditions. Box fill is also more than physical fit. Each insulated conductor counts, all equipment grounds together count as one volume allowance, and devices or internal clamps can add more volume to the calculation.', '{"necReferences":["300.11","314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dd5dd63a-b1ac-4e06-a80e-4ed146fd9525', 'e7f99f77-30e4-464e-9ede-d016be784019', 5, 'paragraph', 'NEC / code relevance', 'NEC 300.11 covers securing and supporting raceways, cable assemblies, and boxes. NEC 314.16 covers box fill. Together they test whether you understand both the outside of the installation and the inside of the box.', 'NEC 300.11 covers securing and supporting raceways, cable assemblies, and boxes. NEC 314.16 covers box fill. Together they test whether you understand both the outside of the installation and the inside of the box.', '{"necReferences":["300.11","314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('561fcb7a-e7ce-4d35-a131-4b8bfe10e0d6', 'e7f99f77-30e4-464e-9ede-d016be784019', 6, 'paragraph', 'Practical example', 'A switch box may look roomy until you count two current-carrying conductors, a switched leg, all grounds together, an internal clamp, and the device yoke. The switch might still fit physically, but the code answer depends on the conductor-volume count, not on whether you can force the device into the opening.', 'A switch box may look roomy until you count two current-carrying conductors, a switched leg, all grounds together, an internal clamp, and the device yoke. The switch might still fit physically, but the code answer depends on the conductor-volume count, not on whether you can force the device into the opening.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('617f6a08-045e-4f0c-826f-3dc3a44e7028', 'e7f99f77-30e4-464e-9ede-d016be784019', 7, 'paragraph', 'Common mistakes', 'A common mistake is choosing the wiring method by habit instead of by location. Another is assuming a bigger-looking box is automatically compliant. Exam problems often hide the real answer inside support details, conductor count, clamps, or device yokes.', 'A common mistake is choosing the wiring method by habit instead of by location. Another is assuming a bigger-looking box is automatically compliant. Exam problems often hide the real answer inside support details, conductor count, clamps, or device yokes.', '{"necReferences":["300.11","314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fe9c7ce4-2938-4fb0-b194-0876e70d5ce8', 'e7f99f77-30e4-464e-9ede-d016be784019', 8, 'paragraph', 'Exam insight', 'Slow down when the question mentions support, concealed versus exposed work, clamps, grounds, or devices in the same box. Those small details usually decide whether the tested concept is permitted use, support, or box fill.', 'Slow down when the question mentions support, concealed versus exposed work, clamps, grounds, or devices in the same box. Those small details usually decide whether the tested concept is permitted use, support, or box fill.', '{"necReferences":["300.11","314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1849a230-d556-4f4e-aba4-6bb92dfafd34', 'e7f99f77-30e4-464e-9ede-d016be784019', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fe80f2db-e745-4c76-8be8-b12396858187', 'e7f99f77-30e4-464e-9ede-d016be784019', 10, 'bullet', NULL, 'Raceways, cable assemblies, and boxes each solve different installation problems.', 'Raceways, cable assemblies, and boxes each solve different installation problems.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('91b39420-32c4-4015-8e0d-f57b7e0b974c', 'e7f99f77-30e4-464e-9ede-d016be784019', 11, 'bullet', NULL, 'Support rules and box-fill rules are both practical Chapter 3 topics.', 'Support rules and box-fill rules are both practical Chapter 3 topics.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5e8c3670-d16d-4499-bb55-7cc56874941a', 'e7f99f77-30e4-464e-9ede-d016be784019', 12, 'bullet', NULL, 'Physical fit is not the same thing as code-compliant box volume.', 'Physical fit is not the same thing as code-compliant box volume.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b7c9dc59-088d-45e6-b8e3-bb5d2c3c7ad2', 'e7f99f77-30e4-464e-9ede-d016be784019', 13, 'bullet', NULL, 'Small details like clamps, grounds, and device yokes can change the correct answer.', 'Small details like clamps, grounds, and device yokes can change the correct answer.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dbb18529-0e61-4a82-8a9a-40ce73e2958a', 'e7f99f77-30e4-464e-9ede-d016be784019', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('99417f91-c5ee-48d0-9379-3545ea93939c', 'e7f99f77-30e4-464e-9ede-d016be784019', 15, 'callout', 'Question 1', 'Why can a box fail the code even when the switch or receptacle still fits inside it?', 'Why can a box fail the code even when the switch or receptacle still fits inside it?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('90212311-fca5-4d8c-b9c7-9122b0b9d893', 'e7f99f77-30e4-464e-9ede-d016be784019', 16, 'callout', 'Question 2', 'What is one practical difference between choosing a raceway and choosing a cable assembly?', 'What is one practical difference between choosing a raceway and choosing a cable assembly?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('43234e2b-1687-43c9-a6f5-9778e9e2f746', 'e7f99f77-30e4-464e-9ede-d016be784019', 17, 'callout', 'Question 3', 'When a question mentions support, clamps, and conductors in the same setup, what should you slow down and identify first?', 'When a question mentions support, clamps, and conductors in the same setup, what should you slow down and identify first?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2f98ebee-a082-4afe-a5b8-8964ab428401', 'a634384e-cd8a-4305-acc1-7001313e16c9', 1, 'paragraph', 'Learning objective', 'Read conductor sizing tables with more confidence and understand how insulation rating, terminal limits, and ampacity relate to one another.', 'Read conductor sizing tables with more confidence and understand how insulation rating, terminal limits, and ampacity relate to one another.', '{"necReferences":["310.14","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('562f1764-f17d-4156-9713-542b9e2f435e', 'a634384e-cd8a-4305-acc1-7001313e16c9', 2, 'paragraph', 'Why this matters', 'Wire sizing is one of the first places where new learners feel buried by tables. Exams reward students who know what the table is actually telling them and what conditions can reduce the usable ampacity.', 'Wire sizing is one of the first places where new learners feel buried by tables. Exams reward students who know what the table is actually telling them and what conditions can reduce the usable ampacity.', '{"necReferences":["310.14","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('48181581-275d-4625-90ff-b55b8b67ddf5', 'a634384e-cd8a-4305-acc1-7001313e16c9', 3, 'paragraph', 'Core explanation', 'Ampacity is the amount of current a conductor can carry continuously under stated conditions without exceeding its temperature rating. NEC Table 310.16 gives base ampacity values, but you still have to read the row and the temperature columns correctly. Material, conductor size, insulation rating, termination limits, and conditions of use all matter before you call the answer final.', 'Ampacity is the amount of current a conductor can carry continuously under stated conditions without exceeding its temperature rating. NEC Table 310.16 gives base ampacity values, but you still have to read the row and the temperature columns correctly. Material, conductor size, insulation rating, termination limits, and conditions of use all matter before you call the answer final.', '{"necReferences":["310.14","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('df294daa-3a18-402d-9542-5d7cb3e4ee09', 'a634384e-cd8a-4305-acc1-7001313e16c9', 4, 'paragraph', 'Key concepts', 'The highest temperature column is not automatically the answer you can use in the field. A conductor may have 90-degree insulation, but the connected equipment may still limit the final ampacity to a lower temperature basis. Table use is a process: identify the conductor, choose the correct row, respect the terminal limit, and then remember that adjustment or correction rules may still apply afterward.', 'The highest temperature column is not automatically the answer you can use in the field. A conductor may have 90-degree insulation, but the connected equipment may still limit the final ampacity to a lower temperature basis. Table use is a process: identify the conductor, choose the correct row, respect the terminal limit, and then remember that adjustment or correction rules may still apply afterward.', '{"necReferences":["310.14","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1c840bd7-d0f3-4737-a954-6b55b0b600ba', 'a634384e-cd8a-4305-acc1-7001313e16c9', 5, 'paragraph', 'NEC / code relevance', 'NEC 310.14 points you to the proper ampacity-selection rules. NEC 310.16 gives the base table values. Together they teach an important exam habit: the table is the starting point, but the installation conditions decide whether that table value can stand unchanged.', 'NEC 310.14 points you to the proper ampacity-selection rules. NEC 310.16 gives the base table values. Together they teach an important exam habit: the table is the starting point, but the installation conditions decide whether that table value can stand unchanged.', '{"necReferences":["310.14","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5c396d65-aac8-42bc-9d8a-7b6170874495', 'a634384e-cd8a-4305-acc1-7001313e16c9', 6, 'paragraph', 'Practical example', 'Suppose you see a conductor row with more than one ampacity listed and immediately pick the biggest number. That feels efficient, but it is often the wrong move. A 90-degree-rated conductor does not let you ignore the equipment termination limit or other installation conditions that control the final usable ampacity.', 'Suppose you see a conductor row with more than one ampacity listed and immediately pick the biggest number. That feels efficient, but it is often the wrong move. A 90-degree-rated conductor does not let you ignore the equipment termination limit or other installation conditions that control the final usable ampacity.', '{"necReferences":["310.14","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b75a6612-6958-43ef-89d1-23c453fea4fc', 'a634384e-cd8a-4305-acc1-7001313e16c9', 7, 'paragraph', 'Common mistakes', 'Students often confuse conductor ampacity with breaker size as if they are always identical. Another mistake is jumping to the 90-degree column because it looks safest or strongest. On the exam, the better answer path is to ask what temperature basis the connected equipment actually allows.', 'Students often confuse conductor ampacity with breaker size as if they are always identical. Another mistake is jumping to the 90-degree column because it looks safest or strongest. On the exam, the better answer path is to ask what temperature basis the connected equipment actually allows.', '{"necReferences":["310.14","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2a24952d-f63a-4aaf-8fd9-3aef57ff4d07', 'a634384e-cd8a-4305-acc1-7001313e16c9', 8, 'paragraph', 'Exam insight', 'Many ampacity questions are really process questions in disguise. Identify the conductor, the temperature basis, and any limiting condition before choosing a number from the table. If you skip that order, the distractors start to look correct.', 'Many ampacity questions are really process questions in disguise. Identify the conductor, the temperature basis, and any limiting condition before choosing a number from the table. If you skip that order, the distractors start to look correct.', '{"necReferences":["310.14","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('27e86457-4ac1-4d22-ad08-ba642fd2cf17', 'a634384e-cd8a-4305-acc1-7001313e16c9', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f0c7aa86-9177-44ef-89ce-304167a72d62', 'a634384e-cd8a-4305-acc1-7001313e16c9', 10, 'bullet', NULL, 'Ampacity is a temperature-based carrying limit, not just a memorized number.', 'Ampacity is a temperature-based carrying limit, not just a memorized number.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('728429d1-e6e3-4903-b582-796d129e9ff3', 'a634384e-cd8a-4305-acc1-7001313e16c9', 11, 'bullet', NULL, 'Table 310.16 gives base values, not automatic final answers.', 'Table 310.16 gives base values, not automatic final answers.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('76dfaa33-07f6-41b9-844b-ee1460a94e77', 'a634384e-cd8a-4305-acc1-7001313e16c9', 12, 'bullet', NULL, 'Termination limits can keep you from using the highest column in the row.', 'Termination limits can keep you from using the highest column in the row.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('01bd09f6-d244-4bbe-8bdf-36e79c9d07a0', 'a634384e-cd8a-4305-acc1-7001313e16c9', 13, 'bullet', NULL, 'Good table work follows an order instead of chasing the biggest number.', 'Good table work follows an order instead of chasing the biggest number.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('631368e8-ee09-46b4-a06d-16eacaec27ef', 'a634384e-cd8a-4305-acc1-7001313e16c9', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('294f07ec-9d22-445c-971c-4a1e7fe4a874', 'a634384e-cd8a-4305-acc1-7001313e16c9', 15, 'callout', 'Question 1', 'Why can the 90-degree column still be the wrong final answer even when the conductor insulation is 90-degree rated?', 'Why can the 90-degree column still be the wrong final answer even when the conductor insulation is 90-degree rated?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8d9555fa-ccbb-4a5e-ae2c-dec28306382d', 'a634384e-cd8a-4305-acc1-7001313e16c9', 16, 'callout', 'Question 2', 'What information should you identify before you trust an ampacity value from Table 310.16?', 'What information should you identify before you trust an ampacity value from Table 310.16?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ebd06ad5-98dc-40ae-9772-bbceabca44fe', 'a634384e-cd8a-4305-acc1-7001313e16c9', 17, 'callout', 'Question 3', 'How is conductor ampacity reasoning different from simply memorizing common breaker sizes?', 'How is conductor ampacity reasoning different from simply memorizing common breaker sizes?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7969a2ad-ac3d-4319-b67d-b7abf808882a', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 1, 'paragraph', 'Learning objective', 'Use NEC hierarchy correctly by separating general rules from special rules and recognizing when a later article changes the normal answer path.', 'Use NEC hierarchy correctly by separating general rules from special rules and recognizing when a later article changes the normal answer path.', '{"necReferences":["90.3","110.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3ff51656-6510-49f9-9950-cd8a882f3d5c', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 2, 'paragraph', 'Why this matters', 'Journeyman exams stop rewarding simple recognition alone. They often test whether you know which rule governs when two sections seem to compete. That is really a hierarchy problem.', 'Journeyman exams stop rewarding simple recognition alone. They often test whether you know which rule governs when two sections seem to compete. That is really a hierarchy problem.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3ab45332-564e-4a52-b975-b42bba20b8e6', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 3, 'paragraph', 'Core explanation', 'General rules usually live in Chapters 1 through 4. Special occupancies, equipment, and conditions are often in Chapters 5 through 7. NEC 90.3 tells you that those later chapters can supplement or modify the general chapters. That means a correct general answer can still become wrong if a special article applies to the situation.', 'General rules usually live in Chapters 1 through 4. Special occupancies, equipment, and conditions are often in Chapters 5 through 7. NEC 90.3 tells you that those later chapters can supplement or modify the general chapters. That means a correct general answer can still become wrong if a special article applies to the situation.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ab2d426d-f32c-413c-9961-555e21780c52', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 4, 'paragraph', 'Key concepts', 'Start with the general rule so you understand the normal requirement. Then ask whether the location, equipment, or condition is special enough to trigger another article. Approval, suitability, and product listing still matter along the way. Strong code reasoning is layered, not one-dimensional.', 'Start with the general rule so you understand the normal requirement. Then ask whether the location, equipment, or condition is special enough to trigger another article. Approval, suitability, and product listing still matter along the way. Strong code reasoning is layered, not one-dimensional.', '{"necReferences":["90.3","110.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4527e977-8d86-44c6-b807-35306195ba8c', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 5, 'paragraph', 'NEC / code relevance', 'NEC 90.3 is the hierarchy rule that keeps code users from getting lost. NEC 110.2 adds the approval lens. Even if you find a rule that seems to permit something, the equipment still has to be acceptable for that use and jurisdiction.', 'NEC 90.3 is the hierarchy rule that keeps code users from getting lost. NEC 110.2 adds the approval lens. Even if you find a rule that seems to permit something, the equipment still has to be acceptable for that use and jurisdiction.', '{"necReferences":["90.3","110.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dd21453b-7416-4adb-865d-bdd7da3f2c4d', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 6, 'paragraph', 'Practical example', 'A wiring method may be acceptable under a general Chapter 3 rule, but a hazardous location article may impose a narrower rule for the same material. The right process is not to argue with the general rule. It is to recognize that the special article controls in that condition.', 'A wiring method may be acceptable under a general Chapter 3 rule, but a hazardous location article may impose a narrower rule for the same material. The right process is not to argue with the general rule. It is to recognize that the special article controls in that condition.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2735b963-b4cd-42df-8565-6c28d6743f1d', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 7, 'paragraph', 'Common mistakes', 'A frequent mistake is stopping after reading a familiar general section. Another is assuming the last section read is always the most specific. You have to decide whether it actually applies to the facts in the question.', 'A frequent mistake is stopping after reading a familiar general section. Another is assuming the last section read is always the most specific. You have to decide whether it actually applies to the facts in the question.', '{"necReferences":["90.3","110.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7b7ddb31-e626-4a7d-aa76-05db0c3169d8', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 8, 'paragraph', 'Exam insight', 'Expect question stems that hide the special condition in a few words. Phrases about hazardous areas, health care spaces, marinas, agricultural buildings, or emergency systems often mean you need to move beyond the general rule.', 'Expect question stems that hide the special condition in a few words. Phrases about hazardous areas, health care spaces, marinas, agricultural buildings, or emergency systems often mean you need to move beyond the general rule.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('26542356-a409-48e5-a22d-f7e0ccae9bb3', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f94b1431-c17d-4734-9318-16b6b4222360', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 10, 'bullet', NULL, 'General rules do not automatically control when a special article applies.', 'General rules do not automatically control when a special article applies.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c436be09-1c22-4d66-8ff5-b6a2f2afb604', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 11, 'bullet', NULL, 'NEC 90.3 is the roadmap for rule hierarchy.', 'NEC 90.3 is the roadmap for rule hierarchy.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ea11ef47-cb9f-4129-aff2-f63b8ee7d458', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 12, 'bullet', NULL, 'Approval and suitability still matter even after you find the right article.', 'Approval and suitability still matter even after you find the right article.', '{}'::jsonb);
