INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d10e5332-4e87-4bdf-abe9-16b3b57a4f48', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 15, 'callout', 'Question 1', 'Why can a correct Chapter 3 rule still lead to the wrong final answer?', 'Why can a correct Chapter 3 rule still lead to the wrong final answer?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2cc79475-797f-4306-8670-9ffe0e5ff94c', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 16, 'callout', 'Question 2', 'What does NEC 90.3 help you decide during a code lookup?', 'What does NEC 90.3 help you decide during a code lookup?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c955ebd8-815d-498d-8c09-73903eaf1ac5', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 17, 'callout', 'Question 3', 'What kind of words in a question suggest you may need a special article?', 'What kind of words in a question suggest you may need a special article?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('50a2fc6e-40b5-4da0-8459-c627754aba8b', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 1, 'paragraph', 'Learning objective', 'Build a faster, repeatable code-lookup method for timed open-book exams by using article patterns, key words, and examples wisely.', 'Build a faster, repeatable code-lookup method for timed open-book exams by using article patterns, key words, and examples wisely.', '{"necReferences":["Article 100","Annex D"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('00ad1f6c-aeaf-4346-b4e1-a8b93b382f40', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 2, 'paragraph', 'Why this matters', 'Timed open-book exams punish wandering. The candidate who knows how to narrow the search wins back minutes that can be used on calculations and review.', 'Timed open-book exams punish wandering. The candidate who knows how to narrow the search wins back minutes that can be used on calculations and review.', '{"necReferences":["Article 100","Annex D"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f2943853-2555-4632-9e80-752d732cbb97', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 3, 'paragraph', 'Core explanation', 'Fast code lookup starts before you open the book. Identify the subject, the equipment type, and whether the problem is about definitions, installation rules, or calculations. Use the index to narrow the article, then confirm the exact section by reading titles and subsection structure carefully. Annex D can help when the question is calculation-shaped, but it is a guide, not the enforceable rule itself.', 'Fast code lookup starts before you open the book. Identify the subject, the equipment type, and whether the problem is about definitions, installation rules, or calculations. Use the index to narrow the article, then confirm the exact section by reading titles and subsection structure carefully. Annex D can help when the question is calculation-shaped, but it is a guide, not the enforceable rule itself.', '{"necReferences":["Article 100","Annex D"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d28e2f97-881b-4f03-9efb-9af9277106f2', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 4, 'paragraph', 'Key concepts', 'Pattern recognition matters. Receptacles often point you toward Article 210. Motors point to Article 430. Grounding questions point to Article 250. If a question depends on what a term means, Article 100 is still one of the fastest first stops. When you practice enough, code lookup becomes a map, not a maze.', 'Pattern recognition matters. Receptacles often point you toward Article 210. Motors point to Article 430. Grounding questions point to Article 250. If a question depends on what a term means, Article 100 is still one of the fastest first stops. When you practice enough, code lookup becomes a map, not a maze.', '{"necReferences":["Article 100","Annex D"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('586ec17f-79b2-4ac9-a3fe-f3305010a508', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 5, 'paragraph', 'NEC / code relevance', 'Article 100 remains the definition anchor. Annex D helps you see how certain calculation methods are applied in example form. It is useful for learning the path, but the enforceable answer still belongs to the governing article and section.', 'Article 100 remains the definition anchor. Annex D helps you see how certain calculation methods are applied in example form. It is useful for learning the path, but the enforceable answer still belongs to the governing article and section.', '{"necReferences":["Article 100","Annex D"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2a0e1a66-8f3e-4f00-a9c3-2156aa8aa10c', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 6, 'paragraph', 'Practical example', 'A calculation question on dwelling-unit service size may feel intimidating, but the keywords optional calculation, dwelling unit, and service should immediately push you toward Article 220, not a random table in Chapter 3. That time-saving recognition is a learned skill.', 'A calculation question on dwelling-unit service size may feel intimidating, but the keywords optional calculation, dwelling unit, and service should immediately push you toward Article 220, not a random table in Chapter 3. That time-saving recognition is a learned skill.', '{"necReferences":["Annex D"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e7446b88-96b0-4f51-bb1a-5538321ab966', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 7, 'paragraph', 'Common mistakes', 'Students lose time by chasing every keyword instead of the main subject. Another mistake is relying on memory of page layout instead of reading titles and section numbers carefully. Under pressure, close answer choices punish sloppy navigation.', 'Students lose time by chasing every keyword instead of the main subject. Another mistake is relying on memory of page layout instead of reading titles and section numbers carefully. Under pressure, close answer choices punish sloppy navigation.', '{"necReferences":["Article 100","Annex D"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7c7a33c7-407a-4666-8dfb-d938dc9fe90c', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 8, 'paragraph', 'Exam insight', 'Practice timed lookups with a notebook beside you. Write the search path after each question. Over time, you will start seeing repeat routes, and those routes are where open-book speed comes from.', 'Practice timed lookups with a notebook beside you. Write the search path after each question. Over time, you will start seeing repeat routes, and those routes are where open-book speed comes from.', '{"necReferences":["Article 100","Annex D"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('38f9a06d-8e8e-4374-9b9e-d94b92458c74', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3aaa2a9a-c3c9-4381-9656-a2ec9015132c', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 10, 'bullet', NULL, 'Timed code lookup is a search strategy, not just a memory test.', 'Timed code lookup is a search strategy, not just a memory test.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b85f58c3-a449-4ec1-8f9e-1dd904a705df', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 11, 'bullet', NULL, 'Start by identifying the subject and the type of question.', 'Start by identifying the subject and the type of question.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('88410837-da43-4cea-b768-9b12d86ca7ad', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 12, 'bullet', NULL, 'Article 100 helps with definitions, and Annex D helps with example-driven calculations.', 'Article 100 helps with definitions, and Annex D helps with example-driven calculations.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1e4ca8f7-38de-4c91-a9c3-fd57dd240195', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 13, 'bullet', NULL, 'Pattern recognition is one of the biggest open-book advantages.', 'Pattern recognition is one of the biggest open-book advantages.', '{}'::jsonb);
