INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('11f2bcf9-d2f2-493a-8a60-c85738731889', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 15, 'callout', 'Question 1', 'What is the first thing you should identify before opening the code book on a timed exam?', 'What is the first thing you should identify before opening the code book on a timed exam?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7c88a6fb-4f4f-4754-8e59-dfdc699d6f83', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 16, 'callout', 'Question 2', 'Why is Annex D helpful but not a substitute for the governing rule?', 'Why is Annex D helpful but not a substitute for the governing rule?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('50ee04bd-1572-4627-b62a-f9e7d79c29c3', 'dd2810b6-f800-413a-b5d8-1dc15de2bab0', 17, 'callout', 'Question 3', 'How does article pattern recognition save time during open-book testing?', 'How does article pattern recognition save time during open-book testing?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cecdcc78-a98e-4d9b-9ffb-ffe11f5cafdc', '38a5b1ac-e91d-491f-b720-75c70d567b19', 1, 'paragraph', 'Learning objective', 'Apply continuous-load logic to branch circuits and feeders so conductor sizing and overcurrent-device sizing stay in the right order.', 'Apply continuous-load logic to branch circuits and feeders so conductor sizing and overcurrent-device sizing stay in the right order.', '{"necReferences":["210.19(A)(1)","210.20(A)","215.2","215.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2b46ca22-27df-4f85-b54a-70605f3e224d', '38a5b1ac-e91d-491f-b720-75c70d567b19', 2, 'paragraph', 'Why this matters', 'This topic shows up constantly because it blends code language, arithmetic, and logic. A student may know the 125 percent rule but still miss the question by applying it to the wrong component.', 'This topic shows up constantly because it blends code language, arithmetic, and logic. A student may know the 125 percent rule but still miss the question by applying it to the wrong component.', '{"necReferences":["210.19(A)(1)","210.20(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8cc8cc55-5c42-43ac-a1a8-59b27d54932c', '38a5b1ac-e91d-491f-b720-75c70d567b19', 3, 'paragraph', 'Core explanation', 'A continuous load is one where the maximum current is expected to continue for 3 hours or more. The NEC requires branch-circuit conductors and feeders for these loads to be sized differently from short-duration loads. Conductors and overcurrent devices each have their own rules, and the exam often checks whether you know which section controls which piece of the design.', 'A continuous load is one where the maximum current is expected to continue for 3 hours or more. The NEC requires branch-circuit conductors and feeders for these loads to be sized differently from short-duration loads. Conductors and overcurrent devices each have their own rules, and the exam often checks whether you know which section controls which piece of the design.', '{"necReferences":["Article 100","210.19(A)(1)","210.20(A)","215.2","215.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5933dd55-a38f-4720-a9ce-896a74a2650c', '38a5b1ac-e91d-491f-b720-75c70d567b19', 4, 'paragraph', 'Key concepts', 'Do not lump branch circuits and feeders together without checking the article. Do not lump conductors and breakers together either. The most important habit is to identify the load type first, then choose the section for conductor sizing, then choose the section for overcurrent protection.', 'Do not lump branch circuits and feeders together without checking the article. Do not lump conductors and breakers together either. The most important habit is to identify the load type first, then choose the section for conductor sizing, then choose the section for overcurrent protection.', '{"necReferences":["210.19(A)(1)","210.20(A)","215.2","215.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('919012b6-6762-4967-8dd8-5fbcd17deec9', '38a5b1ac-e91d-491f-b720-75c70d567b19', 5, 'paragraph', 'NEC / code relevance', 'Article 100 defines continuous load. NEC 210.19(A)(1) and 210.20(A) apply on the branch-circuit side. NEC 215.2 and 215.3 apply on the feeder side. NEC 220.40 reminds you that load calculations are part of the overall answer path.', 'Article 100 defines continuous load. NEC 210.19(A)(1) and 210.20(A) apply on the branch-circuit side. NEC 215.2 and 215.3 apply on the feeder side. NEC 220.40 reminds you that load calculations are part of the overall answer path.', '{"necReferences":["Article 100","210.19(A)(1)","210.20(A)","215.2","215.3","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0d811506-332c-43d9-bf3d-dc0222e4c967', '38a5b1ac-e91d-491f-b720-75c70d567b19', 6, 'paragraph', 'Practical example', 'A 40-amp continuous load on a branch circuit is not handled the same way as a short-duration load. The student has to identify the continuous nature of the load first, then follow the proper branch-circuit conductor and overcurrent sizing rules. Skipping that first step leads to the wrong number even if the arithmetic is clean.', 'A 40-amp continuous load on a branch circuit is not handled the same way as a short-duration load. The student has to identify the continuous nature of the load first, then follow the proper branch-circuit conductor and overcurrent sizing rules. Skipping that first step leads to the wrong number even if the arithmetic is clean.', '{"necReferences":["210.19(A)(1)","210.20(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('428fd12f-4828-473c-8479-01c6b7ffd9cc', '38a5b1ac-e91d-491f-b720-75c70d567b19', 7, 'paragraph', 'Common mistakes', 'The biggest mistake is applying 125 percent to everything in the problem without thinking. Another is using the branch-circuit rule on a feeder question or the feeder rule on a branch-circuit question.', 'The biggest mistake is applying 125 percent to everything in the problem without thinking. Another is using the branch-circuit rule on a feeder question or the feeder rule on a branch-circuit question.', '{"necReferences":["210.19(A)(1)","210.20(A)","215.2","215.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('47dcf0ae-2469-40f6-a7ab-7bbc26ae06f1', '38a5b1ac-e91d-491f-b720-75c70d567b19', 8, 'paragraph', 'Exam insight', 'Continuous-load questions often look easy until you see the answer choices. The test is checking your process. Label each value as branch circuit, feeder, conductor, or overcurrent device before you calculate.', 'Continuous-load questions often look easy until you see the answer choices. The test is checking your process. Label each value as branch circuit, feeder, conductor, or overcurrent device before you calculate.', '{"necReferences":["Article 100","210.20(A)","215.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('57eb0597-91df-4c71-ac90-4fd5cf7dfc47', '38a5b1ac-e91d-491f-b720-75c70d567b19', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('461c8d2b-0a49-4669-973d-6f20447f8c63', '38a5b1ac-e91d-491f-b720-75c70d567b19', 10, 'bullet', NULL, 'A continuous load is expected to run at maximum current for 3 hours or more.', 'A continuous load is expected to run at maximum current for 3 hours or more.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b21329d1-0d0e-4e0a-aa50-0cb7bb159f31', '38a5b1ac-e91d-491f-b720-75c70d567b19', 11, 'bullet', NULL, 'Branch-circuit and feeder rules are related but not identical.', 'Branch-circuit and feeder rules are related but not identical.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2c458e36-1642-4bc8-9612-c61dbe891252', '38a5b1ac-e91d-491f-b720-75c70d567b19', 12, 'bullet', NULL, 'Conductor sizing and overcurrent-device sizing must be handled in the right order.', 'Conductor sizing and overcurrent-device sizing must be handled in the right order.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('46e2aaec-7926-4491-931f-998e6e04a407', '38a5b1ac-e91d-491f-b720-75c70d567b19', 13, 'bullet', NULL, 'Most misses happen because students apply one rule to the wrong component.', 'Most misses happen because students apply one rule to the wrong component.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8a733aa3-2b8e-4428-8a87-a7b17d8a6838', '38a5b1ac-e91d-491f-b720-75c70d567b19', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ae9c4484-6a0d-43fb-b755-ecb391f6dee7', '38a5b1ac-e91d-491f-b720-75c70d567b19', 15, 'callout', 'Question 1', 'What defined term tells you whether the 3-hour rule applies?', 'What defined term tells you whether the 3-hour rule applies?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cf6fd5b8-51c8-4fae-a39e-d42e0f284376', '38a5b1ac-e91d-491f-b720-75c70d567b19', 16, 'callout', 'Question 2', 'Why is it risky to apply 125 percent to every number in the problem automatically?', 'Why is it risky to apply 125 percent to every number in the problem automatically?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('809fd25e-6f71-4b67-80f6-520987265487', '38a5b1ac-e91d-491f-b720-75c70d567b19', 17, 'callout', 'Question 3', 'What is the difference between the branch-circuit path and the feeder path for continuous loads?', 'What is the difference between the branch-circuit path and the feeder path for continuous loads?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d6d3ff29-16cf-4fa7-ba12-3545328cf5a1', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 1, 'paragraph', 'Learning objective', 'Explain the purpose of required dwelling-unit branch circuits and use the basic receptacle-placement rules in Article 210 with better accuracy.', 'Explain the purpose of required dwelling-unit branch circuits and use the basic receptacle-placement rules in Article 210 with better accuracy.', '{"necReferences":["210.11","210.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bb95f832-c496-4610-880a-a80c91a34896', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 2, 'paragraph', 'Why this matters', 'Dwelling-unit questions are frequent because they connect everyday residential layouts to code decisions. They are also easy points for candidates who can separate required circuits from required outlet placement instead of treating Article 210 like one giant memorization problem.', 'Dwelling-unit questions are frequent because they connect everyday residential layouts to code decisions. They are also easy points for candidates who can separate required circuits from required outlet placement instead of treating Article 210 like one giant memorization problem.', '{"necReferences":["210.11","210.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4292f1f7-66bd-4838-ae58-89916350e779', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 3, 'paragraph', 'Core explanation', 'Article 210 does more than talk about receptacles. It also requires certain dwelling-unit branch circuits to serve specific areas and uses. For example, dwelling kitchens and related areas require dedicated small-appliance circuit planning, while bathrooms and laundry areas have their own required branch-circuit treatment. Receptacle placement rules then decide where outlets must be located so occupants are not forced into unsafe extension-cord habits.', 'Article 210 does more than talk about receptacles. It also requires certain dwelling-unit branch circuits to serve specific areas and uses. For example, dwelling kitchens and related areas require dedicated small-appliance circuit planning, while bathrooms and laundry areas have their own required branch-circuit treatment. Receptacle placement rules then decide where outlets must be located so occupants are not forced into unsafe extension-cord habits.', '{"necReferences":["210.11","210.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3b9a8470-2211-4a7a-b686-ac836e913de6', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 4, 'paragraph', 'Key concepts', 'Required circuits and required receptacle locations are related but different questions. One asks what kind of branch-circuit capacity the dwelling must have. The other asks where outlets must be placed. The familiar 6-foot and 12-foot wall-space logic helps with general wall spaces, but countertop areas, bathrooms, laundry areas, and similar spaces can trigger different rule paths.', 'Required circuits and required receptacle locations are related but different questions. One asks what kind of branch-circuit capacity the dwelling must have. The other asks where outlets must be placed. The familiar 6-foot and 12-foot wall-space logic helps with general wall spaces, but countertop areas, bathrooms, laundry areas, and similar spaces can trigger different rule paths.', '{"necReferences":["210.11","210.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b2719b80-a7f9-426e-b736-4789f985be7c', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 5, 'paragraph', 'NEC / code relevance', 'NEC 210.11 identifies branch circuits that are specifically required in dwelling units. NEC 210.52 covers minimum receptacle placement. Together they form one of the most testable residential areas because the exam can ask about circuit purpose, spacing, or a special room in the same problem.', 'NEC 210.11 identifies branch circuits that are specifically required in dwelling units. NEC 210.52 covers minimum receptacle placement. Together they form one of the most testable residential areas because the exam can ask about circuit purpose, spacing, or a special room in the same problem.', '{"necReferences":["210.11","210.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('858bde3c-e369-402e-8540-80275d1ff6ee', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 6, 'paragraph', 'Practical example', 'A 12-foot living-room wall can often be satisfied by one centered receptacle because no point along the floor line ends up more than 6 feet from an outlet. But that same thinking does not answer a kitchen countertop question, because kitchen small-appliance circuits and countertop receptacles follow their own residential rules.', 'A 12-foot living-room wall can often be satisfied by one centered receptacle because no point along the floor line ends up more than 6 feet from an outlet. But that same thinking does not answer a kitchen countertop question, because kitchen small-appliance circuits and countertop receptacles follow their own residential rules.', '{"necReferences":["210.11","210.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6bd4912f-5b4c-41cc-aa96-3005a480a5d1', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 7, 'paragraph', 'Common mistakes', 'The most common mistake is memorizing the wall-space rule and then forcing it onto every dwelling situation. Another is forgetting that required small-appliance, bathroom, and laundry circuit questions are asking about dedicated branch-circuit coverage, not just receptacle spacing.', 'The most common mistake is memorizing the wall-space rule and then forcing it onto every dwelling situation. Another is forgetting that required small-appliance, bathroom, and laundry circuit questions are asking about dedicated branch-circuit coverage, not just receptacle spacing.', '{"necReferences":["210.11","210.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('10051e03-531e-4496-a5e3-a1d721833f4f', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 8, 'paragraph', 'Exam insight', 'When a residential question feels crowded, decide what it is testing before reading the answers twice. Is it asking about wall spacing, a special room, or a required branch circuit? That decision removes a lot of close-sounding distractors fast.', 'When a residential question feels crowded, decide what it is testing before reading the answers twice. Is it asking about wall spacing, a special room, or a required branch circuit? That decision removes a lot of close-sounding distractors fast.', '{"necReferences":["210.11","210.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('27e62f1e-063d-4e78-9825-074317048e7f', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8a778098-3fb8-46ca-a67a-38e781b69ffc', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 10, 'bullet', NULL, 'Required dwelling circuits and receptacle placement rules work together, but they are not the same thing.', 'Required dwelling circuits and receptacle placement rules work together, but they are not the same thing.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3b866b5c-c857-4cf3-9c21-82e4c9e24220', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 11, 'bullet', NULL, 'Article 210 is a major residential exam article because it combines layout and branch-circuit rules.', 'Article 210 is a major residential exam article because it combines layout and branch-circuit rules.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bcf938bb-0b37-4740-8a01-b966f7c13a16', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 12, 'bullet', NULL, 'The general wall-space rule does not answer every kitchen, bathroom, or laundry question.', 'The general wall-space rule does not answer every kitchen, bathroom, or laundry question.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2c14a2ac-53b0-4531-8a2e-3fc52a0f142d', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 13, 'bullet', NULL, 'Start by identifying whether the problem is testing placement, circuit purpose, or a special dwelling area.', 'Start by identifying whether the problem is testing placement, circuit purpose, or a special dwelling area.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2f6ded27-d437-4de4-acc1-7962e73be733', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b6ac4443-f47b-438f-ad80-e2812a7de35e', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 15, 'callout', 'Question 1', 'Why is it a mistake to apply the general wall-space rule to every dwelling-unit question?', 'Why is it a mistake to apply the general wall-space rule to every dwelling-unit question?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('33d03a01-bb52-4f22-aa38-e3fbfcef9ca7', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 16, 'callout', 'Question 2', 'What is the difference between a required branch circuit and a required receptacle location?', 'What is the difference between a required branch circuit and a required receptacle location?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e5bc2fcc-70c6-4df5-a1a7-88c93863b177', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 17, 'callout', 'Question 3', 'If a problem mentions kitchen countertop receptacles and small-appliance circuits together, what should you identify first?', 'If a problem mentions kitchen countertop receptacles and small-appliance circuits together, what should you identify first?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b1ab21f3-c752-4f95-816a-e700e183f6fd', '71144249-a131-40b6-b7ce-33ff65c69919', 1, 'paragraph', 'Learning objective', 'Separate grounding from bonding at the service and feeder level so you can follow the fault-current path and earth-reference path without mixing them up.', 'Separate grounding from bonding at the service and feeder level so you can follow the fault-current path and earth-reference path without mixing them up.', '{"necReferences":["250.24","250.32","250.50"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f705fdd4-f65b-466c-ac49-29a751ead1c9', '71144249-a131-40b6-b7ce-33ff65c69919', 2, 'paragraph', 'Why this matters', 'Grounding and bonding is one of the most misunderstood electrician exam topics. Students often know pieces of the vocabulary but cannot explain the function of each conductor or connection point.', 'Grounding and bonding is one of the most misunderstood electrician exam topics. Students often know pieces of the vocabulary but cannot explain the function of each conductor or connection point.', '{"necReferences":["250.24","250.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('20a08514-b2f4-4292-a2ed-24eca845886a', '71144249-a131-40b6-b7ce-33ff65c69919', 3, 'paragraph', 'Core explanation', 'Grounding and bonding work together, but they do not do the same job. The grounded service conductor, service bonding jumper, equipment grounding conductor, and grounding electrode system each have a specific role. At the service, the code brings system grounding and bonding together in a defined way. At feeders and separate buildings, the rules shift because the source point and return path are different.', 'Grounding and bonding work together, but they do not do the same job. The grounded service conductor, service bonding jumper, equipment grounding conductor, and grounding electrode system each have a specific role. At the service, the code brings system grounding and bonding together in a defined way. At feeders and separate buildings, the rules shift because the source point and return path are different.', '{"necReferences":["250.24","250.32","250.50"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5723a870-c059-4e36-b805-10ad04aca4aa', '71144249-a131-40b6-b7ce-33ff65c69919', 4, 'paragraph', 'Key concepts', 'The grounding electrode system connects the electrical system to earth. Bonding ties conductive parts together so fault current has an effective low-impedance path back to the source. If you cannot explain where fault current is supposed to travel, you probably do not understand the bonding part yet.', 'The grounding electrode system connects the electrical system to earth. Bonding ties conductive parts together so fault current has an effective low-impedance path back to the source. If you cannot explain where fault current is supposed to travel, you probably do not understand the bonding part yet.', '{"necReferences":["250.24","250.32","250.50"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8ad8bc1b-a162-4b39-b31d-006b966cd929', '71144249-a131-40b6-b7ce-33ff65c69919', 5, 'paragraph', 'NEC / code relevance', 'NEC 250.24 covers service grounding and bonding. NEC 250.32 applies to buildings or structures supplied by feeders. NEC 250.50 describes the grounding electrode system. These sections are tested together because the exam wants functional understanding, not just word recognition.', 'NEC 250.24 covers service grounding and bonding. NEC 250.32 applies to buildings or structures supplied by feeders. NEC 250.50 describes the grounding electrode system. These sections are tested together because the exam wants functional understanding, not just word recognition.', '{"necReferences":["250.24","250.32","250.50"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('639da0c4-bc76-4f6c-a0ee-d2136bdbcff3', '71144249-a131-40b6-b7ce-33ff65c69919', 6, 'paragraph', 'Practical example', 'If a fault energizes a metal enclosure, the equipment bonding path should carry that fault current back to the source quickly enough to operate the protective device. Earth is not supposed to be the normal fault-clearing path for that enclosure. That is a core exam distinction.', 'If a fault energizes a metal enclosure, the equipment bonding path should carry that fault current back to the source quickly enough to operate the protective device. Earth is not supposed to be the normal fault-clearing path for that enclosure. That is a core exam distinction.', '{"necReferences":["250.24","250.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('70ed5c95-bb09-4317-addc-9e5bf8e3e6af', '71144249-a131-40b6-b7ce-33ff65c69919', 7, 'paragraph', 'Common mistakes', 'Students often say grounding clears faults and stop there. That answer is incomplete and usually wrong in the exam sense. Another mistake is using service rules at a feeder-supplied detached structure without checking the separate-building rules carefully.', 'Students often say grounding clears faults and stop there. That answer is incomplete and usually wrong in the exam sense. Another mistake is using service rules at a feeder-supplied detached structure without checking the separate-building rules carefully.', '{"necReferences":["250.24","250.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('abffd422-ad86-472e-8e2a-a5d60d24841e', '71144249-a131-40b6-b7ce-33ff65c69919', 8, 'paragraph', 'Exam insight', 'When the answer choices sound similar, ask yourself two questions: is this about reference to earth, or is it about returning fault current to the source? That question alone removes a lot of wrong options.', 'When the answer choices sound similar, ask yourself two questions: is this about reference to earth, or is it about returning fault current to the source? That question alone removes a lot of wrong options.', '{"necReferences":["250.24","250.32","250.50"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('83bc6326-1cdf-4eef-aed9-32ea23b43214', '71144249-a131-40b6-b7ce-33ff65c69919', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('518129e0-572d-429e-871b-60f5d7fa36c8', '71144249-a131-40b6-b7ce-33ff65c69919', 10, 'bullet', NULL, 'Grounding and bonding are related but different functions.', 'Grounding and bonding are related but different functions.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8d7a4378-cedb-44e3-add2-371ab7ea22d3', '71144249-a131-40b6-b7ce-33ff65c69919', 11, 'bullet', NULL, 'The grounding electrode system is not the same thing as the equipment bonding path.', 'The grounding electrode system is not the same thing as the equipment bonding path.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('167c401f-499c-4471-8a4d-da5306084ac1', '71144249-a131-40b6-b7ce-33ff65c69919', 12, 'bullet', NULL, 'Service rules and feeder-to-building rules are not interchangeable.', 'Service rules and feeder-to-building rules are not interchangeable.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6562bdd1-d6f5-4b1c-906d-db8a0b889b42', '71144249-a131-40b6-b7ce-33ff65c69919', 13, 'bullet', NULL, 'Following the intended fault-current path is the fastest way to reason through tough questions.', 'Following the intended fault-current path is the fastest way to reason through tough questions.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a660c1fe-8fae-40d4-8099-fb79dbc9b83b', '71144249-a131-40b6-b7ce-33ff65c69919', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0f976e1b-c068-48d3-bb89-60c317cf1bf3', '71144249-a131-40b6-b7ce-33ff65c69919', 15, 'callout', 'Question 1', 'Why is earth not the normal fault-clearing path for metal enclosures?', 'Why is earth not the normal fault-clearing path for metal enclosures?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('59cfb86d-48f7-4d8d-a62c-e85f07d8aabb', '71144249-a131-40b6-b7ce-33ff65c69919', 16, 'callout', 'Question 2', 'What main code section would you check for a feeder to a separate building?', 'What main code section would you check for a feeder to a separate building?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('82739bab-f8f1-45bd-b6bd-552b127dc4d9', '71144249-a131-40b6-b7ce-33ff65c69919', 17, 'callout', 'Question 3', 'How can you tell whether a question is really about grounding or about bonding?', 'How can you tell whether a question is really about grounding or about bonding?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7076f9a4-1a87-4e97-9b8c-986077d95921', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 1, 'paragraph', 'Learning objective', 'Identify common grounding electrodes and understand how grounding electrode conductors are selected and sized at a practical exam-prep level.', 'Identify common grounding electrodes and understand how grounding electrode conductors are selected and sized at a practical exam-prep level.', '{"necReferences":["250.50","250.66"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ec221340-0f62-40ea-8b3b-046025eae049', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 2, 'paragraph', 'Why this matters', 'This topic appears in both direct code questions and bigger service questions. Students lose easy points when they know electrode names but do not understand the system idea behind them.', 'This topic appears in both direct code questions and bigger service questions. Students lose easy points when they know electrode names but do not understand the system idea behind them.', '{"necReferences":["250.50","250.66"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3c9687c6-f91b-4dc9-aabc-bfefa5e7d082', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 3, 'paragraph', 'Core explanation', 'A building may have more than one qualifying grounding electrode. When electrodes are present, the NEC requires them to be bonded together into one grounding electrode system. The grounding electrode conductor connects the grounded service conductor or derived-system connection point to that system, and its size depends on code rules rather than guesswork.', 'A building may have more than one qualifying grounding electrode. When electrodes are present, the NEC requires them to be bonded together into one grounding electrode system. The grounding electrode conductor connects the grounded service conductor or derived-system connection point to that system, and its size depends on code rules rather than guesswork.', '{"necReferences":["250.50","250.66"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c5259391-176b-49e8-b0a7-cbb1a11be45b', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 4, 'paragraph', 'Key concepts', 'Common electrodes include metal underground water pipe, building steel, concrete-encased electrodes, rods, pipes, plates, and ground rings. The exam often tests whether you know that available electrodes are not optional extras. If they qualify, they become part of the required system. Sizing the grounding electrode conductor is then tied to the code method, not to a casual field estimate.', 'Common electrodes include metal underground water pipe, building steel, concrete-encased electrodes, rods, pipes, plates, and ground rings. The exam often tests whether you know that available electrodes are not optional extras. If they qualify, they become part of the required system. Sizing the grounding electrode conductor is then tied to the code method, not to a casual field estimate.', '{"necReferences":["250.50","250.66"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('303eb89c-3c6f-4d2b-9a4a-8df593458373', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 5, 'paragraph', 'NEC / code relevance', 'NEC 250.50 requires all available electrodes to be bonded together into one system. NEC 250.66 gives sizing rules for grounding electrode conductors. Those two sections are closely linked on exams because one tells you what must exist and the other tells you how the conductor is selected.', 'NEC 250.50 requires all available electrodes to be bonded together into one system. NEC 250.66 gives sizing rules for grounding electrode conductors. Those two sections are closely linked on exams because one tells you what must exist and the other tells you how the conductor is selected.', '{"necReferences":["250.50","250.66"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a86ced81-a6c3-4303-a797-be9df378a834', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 6, 'paragraph', 'Practical example', 'If a building has both qualifying building steel and a concrete-encased electrode, the design conversation is not which one you prefer. The conversation is how the grounding electrode system is formed and how the grounding electrode conductor ties into the required arrangement.', 'If a building has both qualifying building steel and a concrete-encased electrode, the design conversation is not which one you prefer. The conversation is how the grounding electrode system is formed and how the grounding electrode conductor ties into the required arrangement.', '{"necReferences":["250.50","250.66"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('babb88c4-0daa-4070-9f5b-de25e578f856', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 7, 'paragraph', 'Common mistakes', 'Students sometimes think one driven rod solves every grounding-electrode question. That shortcut misses the bigger system concept. Another mistake is forgetting that electrode-conductor sizing follows code rules tied to service-conductor size and electrode type.', 'Students sometimes think one driven rod solves every grounding-electrode question. That shortcut misses the bigger system concept. Another mistake is forgetting that electrode-conductor sizing follows code rules tied to service-conductor size and electrode type.', '{"necReferences":["250.50","250.66"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bff31150-b71f-4caa-b2b8-b4c530a91871', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 8, 'paragraph', 'Exam insight', 'If the question asks what electrodes must be part of the system, think system first. If it asks what size conductor is required, shift to the sizing section and read carefully for the conductor and electrode details.', 'If the question asks what electrodes must be part of the system, think system first. If it asks what size conductor is required, shift to the sizing section and read carefully for the conductor and electrode details.', '{"necReferences":["250.50","250.66"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('db0d2c46-d534-4304-8190-9b27ef820a3b', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2587cf9d-86d8-442f-9fd1-e04d402996d4', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 10, 'bullet', NULL, 'Available qualifying electrodes must be bonded into one grounding electrode system.', 'Available qualifying electrodes must be bonded into one grounding electrode system.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6e6c77e2-9c8c-434b-a2be-606a513b2ded', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 11, 'bullet', NULL, 'A grounding electrode conductor connects the system to that electrode system according to code rules.', 'A grounding electrode conductor connects the system to that electrode system according to code rules.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d92ef30a-124a-4ba7-b23c-07911e2c08f3', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 12, 'bullet', NULL, 'Electrode questions often test system thinking first and sizing second.', 'Electrode questions often test system thinking first and sizing second.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1209e764-b5a5-4de6-8aab-3d1353c0f6c0', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 13, 'bullet', NULL, 'Driven rods are only one part of a broader grounding-electrode picture.', 'Driven rods are only one part of a broader grounding-electrode picture.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('472ba680-cc57-46fb-a291-a7f691647c0f', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4219fb57-941d-40a6-be97-c223f21319ae', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 15, 'callout', 'Question 1', 'Why is a grounding-electrode question often bigger than just one driven rod?', 'Why is a grounding-electrode question often bigger than just one driven rod?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e3fab163-53e3-4a0c-be44-d6bb810e8bc4', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 16, 'callout', 'Question 2', 'Which section tells you that available electrodes must be bonded together?', 'Which section tells you that available electrodes must be bonded together?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('47abdbd4-a780-4a45-b6e0-a024f4b064f9', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 17, 'callout', 'Question 3', 'What is the difference between identifying required electrodes and sizing the grounding electrode conductor?', 'What is the difference between identifying required electrodes and sizing the grounding electrode conductor?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8bf444e0-2fe2-4ad1-9a18-b0657244657e', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 1, 'paragraph', 'Learning objective', 'Use the NEC motor-conductor and overload rules more accurately by understanding why motor circuits are not sized like ordinary branch circuits.', 'Use the NEC motor-conductor and overload rules more accurately by understanding why motor circuits are not sized like ordinary branch circuits.', '{"necReferences":["430.22","430.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a80618be-2413-441f-a76c-2d5ec98bc0b5', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 2, 'paragraph', 'Why this matters', 'Motor questions scare many candidates because the rules feel different from everyday branch-circuit work. The difference is intentional. Motors start, run, and overload in ways that ordinary lighting loads do not.', 'Motor questions scare many candidates because the rules feel different from everyday branch-circuit work. The difference is intentional. Motors start, run, and overload in ways that ordinary lighting loads do not.', '{"necReferences":["430.22","430.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('109443cd-8770-4bed-b451-621a16a5cab1', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 3, 'paragraph', 'Core explanation', 'Motor branch-circuit conductors are typically sized from the NEC motor full-load current tables where the code requires it, not automatically from the nameplate current. Overload protection has a different job from short-circuit and ground-fault protection. Overload protection is there to protect the motor from overheating due to excess running current, not to clear high-level fault current instantly.', 'Motor branch-circuit conductors are typically sized from the NEC motor full-load current tables where the code requires it, not automatically from the nameplate current. Overload protection has a different job from short-circuit and ground-fault protection. Overload protection is there to protect the motor from overheating due to excess running current, not to clear high-level fault current instantly.', '{"necReferences":["430.22","430.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('17f07244-75de-467b-9f14-83e1800be533', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 4, 'paragraph', 'Key concepts', 'Motor conductor sizing, overload protection, and short-circuit protection are three related but separate design steps. The exam often checks whether you know which device is being discussed. If the question says overload, think about protecting the motor windings from excess current over time. If it says branch-circuit short-circuit protection, that is a different code path.', 'Motor conductor sizing, overload protection, and short-circuit protection are three related but separate design steps. The exam often checks whether you know which device is being discussed. If the question says overload, think about protecting the motor windings from excess current over time. If it says branch-circuit short-circuit protection, that is a different code path.', '{"necReferences":["430.22","430.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1d4ef753-4935-421e-bca2-6e487d96a113', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 5, 'paragraph', 'NEC / code relevance', 'NEC 430.22 covers motor branch-circuit conductors. NEC 430.32 covers overload protection. Together they show that motors have their own code logic and should not be treated like a simple resistive load on a standard branch circuit.', 'NEC 430.22 covers motor branch-circuit conductors. NEC 430.32 covers overload protection. Together they show that motors have their own code logic and should not be treated like a simple resistive load on a standard branch circuit.', '{"necReferences":["430.22","430.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('56ceaef3-9815-417c-892c-4ccc705d97b2', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 6, 'paragraph', 'Practical example', 'A motor may need conductors sized by the applicable motor rules while the overload device is set to protect the motor from sustained overcurrent during operation. That can feel strange to students who expect one number to control every part of the circuit design.', 'A motor may need conductors sized by the applicable motor rules while the overload device is set to protect the motor from sustained overcurrent during operation. That can feel strange to students who expect one number to control every part of the circuit design.', '{"necReferences":["430.22","430.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b2771828-a1f2-4141-9e1d-32b7e1e35ccd', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 7, 'paragraph', 'Common mistakes', 'The biggest mistake is using the nameplate current everywhere without checking whether the NEC table value is required. Another is confusing overload protection with the branch-circuit device that handles short circuits and ground faults.', 'The biggest mistake is using the nameplate current everywhere without checking whether the NEC table value is required. Another is confusing overload protection with the branch-circuit device that handles short circuits and ground faults.', '{"necReferences":["430.22","430.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('51855cec-7d48-432f-9357-e665ac45842e', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 8, 'paragraph', 'Exam insight', 'When you see a motor question, write down which of the three jobs is being tested: conductors, overload, or short-circuit protection. That simple habit prevents a lot of wrong turns.', 'When you see a motor question, write down which of the three jobs is being tested: conductors, overload, or short-circuit protection. That simple habit prevents a lot of wrong turns.', '{"necReferences":["430.22","430.32"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6579ee9c-d1e8-4465-91d2-13f59c52a148', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e7353cec-2a8d-4e30-ab95-a18a4e110834', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 10, 'bullet', NULL, 'Motor circuits follow their own NEC logic.', 'Motor circuits follow their own NEC logic.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9fa15094-592e-4695-ac98-d5769ea871b8', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 11, 'bullet', NULL, 'Conductors, overload protection, and short-circuit protection are separate design steps.', 'Conductors, overload protection, and short-circuit protection are separate design steps.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2b2127e6-c836-421c-9e1a-c5fb62c178b9', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 12, 'bullet', NULL, 'Overload protection protects the motor from overheating during operation.', 'Overload protection protects the motor from overheating during operation.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c9a35fb2-77a7-48ad-b457-d8c6f6a87fb5', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 13, 'bullet', NULL, 'Motor questions often turn on whether you should use a table value or another source value.', 'Motor questions often turn on whether you should use a table value or another source value.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3fa67409-96ad-4060-b167-24bc526b27a6', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c11430e6-c273-40c4-a939-70eca708675d', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 15, 'callout', 'Question 1', 'Why is overload protection not the same thing as short-circuit protection in a motor circuit?', 'Why is overload protection not the same thing as short-circuit protection in a motor circuit?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('211856d2-0fc1-4c1f-963a-77445634c658', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 16, 'callout', 'Question 2', 'What is the first question to ask when a motor problem appears on an exam?', 'What is the first question to ask when a motor problem appears on an exam?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('630bc2ba-70a5-4f56-8a7b-c9ba7fdcaf88', 'dcc853e2-a68b-4707-9e4c-a2c62da7ebb1', 17, 'callout', 'Question 3', 'Why can motor circuits feel different from ordinary branch-circuit sizing questions?', 'Why can motor circuits feel different from ordinary branch-circuit sizing questions?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('868e9d24-5b74-46dd-b7d2-1e7ea3059662', 'ed52a359-658b-433e-bba4-0680bf829ff9', 1, 'paragraph', 'Learning objective', 'Understand what motor branch-circuit short-circuit and ground-fault protection is supposed to do and why its sizing rules can look higher than new learners expect.', 'Understand what motor branch-circuit short-circuit and ground-fault protection is supposed to do and why its sizing rules can look higher than new learners expect.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6f7b65a5-4f95-4230-a481-b640dc051c49', 'ed52a359-658b-433e-bba4-0680bf829ff9', 2, 'paragraph', 'Why this matters', 'Students often panic when they see a motor protective-device value that seems larger than the conductor ampacity or overload setting. The rules look unusual only until you understand the purpose of each protective layer.', 'Students often panic when they see a motor protective-device value that seems larger than the conductor ampacity or overload setting. The rules look unusual only until you understand the purpose of each protective layer.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('138d5b01-5e48-41eb-9d41-39683974912a', 'ed52a359-658b-433e-bba4-0680bf829ff9', 3, 'paragraph', 'Core explanation', 'Motor branch-circuit short-circuit and ground-fault protection is designed to protect the circuit against severe fault current and allow the motor to start without nuisance tripping. That is different from overload protection, which protects the motor from excess running current over time. Because the purposes differ, the sizing path also differs.', 'Motor branch-circuit short-circuit and ground-fault protection is designed to protect the circuit against severe fault current and allow the motor to start without nuisance tripping. That is different from overload protection, which protects the motor from excess running current over time. Because the purposes differ, the sizing path also differs.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a142c7cf-562b-42eb-b9e4-35e6f13af083', 'ed52a359-658b-433e-bba4-0680bf829ff9', 4, 'paragraph', 'Key concepts', 'The branch-circuit protective device is not there to perform every protective job by itself. Motor starting current can be high for a short time, so the branch-circuit protection has to be chosen with that operating reality in mind. The code tables and rules exist so the motor can start while still having fault protection.', 'The branch-circuit protective device is not there to perform every protective job by itself. Motor starting current can be high for a short time, so the branch-circuit protection has to be chosen with that operating reality in mind. The code tables and rules exist so the motor can start while still having fault protection.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3d8d4d49-835a-4269-af94-ff34d0e83b7d', 'ed52a359-658b-433e-bba4-0680bf829ff9', 5, 'paragraph', 'NEC / code relevance', 'NEC 430.52 is the key section for motor branch-circuit short-circuit and ground-fault protection. It is heavily tested because it forces candidates to understand purpose, not just memorize a single percentage.', 'NEC 430.52 is the key section for motor branch-circuit short-circuit and ground-fault protection. It is heavily tested because it forces candidates to understand purpose, not just memorize a single percentage.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('08e767b4-c107-46db-a527-c31ab4311204', 'ed52a359-658b-433e-bba4-0680bf829ff9', 6, 'paragraph', 'Practical example', 'A student may be surprised that a motor branch-circuit protective device can be sized differently from the overload device. That is not a contradiction. It reflects the difference between handling startup and clearing a fault versus protecting the motor from long-term overheating.', 'A student may be surprised that a motor branch-circuit protective device can be sized differently from the overload device. That is not a contradiction. It reflects the difference between handling startup and clearing a fault versus protecting the motor from long-term overheating.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9d715d20-302b-4e55-9106-e801b0ac6dfd', 'ed52a359-658b-433e-bba4-0680bf829ff9', 7, 'paragraph', 'Common mistakes', 'A common mistake is calling every motor protective device an overload device. Another is assuming a larger short-circuit protective-device setting is automatically unsafe without understanding why the code allows it in that context.', 'A common mistake is calling every motor protective device an overload device. Another is assuming a larger short-circuit protective-device setting is automatically unsafe without understanding why the code allows it in that context.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('705201e8-ec6d-4569-93c0-97da032da0ac', 'ed52a359-658b-433e-bba4-0680bf829ff9', 8, 'paragraph', 'Exam insight', 'Read the exact words in the question. If it says short-circuit and ground-fault protection, go straight to 430.52 logic. Do not answer with overload language just because it sounds familiar.', 'Read the exact words in the question. If it says short-circuit and ground-fault protection, go straight to 430.52 logic. Do not answer with overload language just because it sounds familiar.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('13d66178-f5fd-4d83-b0a4-3896786da5e6', 'ed52a359-658b-433e-bba4-0680bf829ff9', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a4fc66f8-ad04-4edb-90a2-78b1f85ecf5f', 'ed52a359-658b-433e-bba4-0680bf829ff9', 10, 'bullet', NULL, 'Motor short-circuit protection and overload protection serve different functions.', 'Motor short-circuit protection and overload protection serve different functions.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('740dcd13-4860-44e1-aec2-f02322b21f72', 'ed52a359-658b-433e-bba4-0680bf829ff9', 11, 'bullet', NULL, 'Motor startup current is one reason these rules look different from ordinary circuits.', 'Motor startup current is one reason these rules look different from ordinary circuits.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e5e21c74-8de9-463e-bc22-b19eb7e8d625', 'ed52a359-658b-433e-bba4-0680bf829ff9', 12, 'bullet', NULL, 'Article 430.52 is the main code path for this topic.', 'Article 430.52 is the main code path for this topic.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('96e142a1-314d-4cf2-8f1d-8f92d50916de', 'ed52a359-658b-433e-bba4-0680bf829ff9', 13, 'bullet', NULL, 'The wording of the question tells you which protective job is being tested.', 'The wording of the question tells you which protective job is being tested.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('75a02ce8-7654-4b56-8a88-f7652c7a36bf', 'ed52a359-658b-433e-bba4-0680bf829ff9', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c7b145ca-08b9-4ef6-9e47-6c017fce448a', 'ed52a359-658b-433e-bba4-0680bf829ff9', 15, 'callout', 'Question 1', 'Why can a motor branch-circuit protective device look larger than a learner expects?', 'Why can a motor branch-circuit protective device look larger than a learner expects?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f67c6a39-9656-4c9d-ae4c-cb768980bf14', 'ed52a359-658b-433e-bba4-0680bf829ff9', 16, 'callout', 'Question 2', 'What is the main difference between overload protection and short-circuit protection for motors?', 'What is the main difference between overload protection and short-circuit protection for motors?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2b447c1d-b659-49e8-aace-88de00285cfc', 'ed52a359-658b-433e-bba4-0680bf829ff9', 17, 'callout', 'Question 3', 'If a question says ground-fault and short-circuit protection, which section should guide your search?', 'If a question says ground-fault and short-circuit protection, which section should guide your search?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ec207dc9-7366-4ca3-8fa1-34eeb89540d3', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 1, 'paragraph', 'Learning objective', 'Follow a service-and-feeder design workflow that starts with load identification, moves through calculation logic, and ends with conductor and equipment decisions.', 'Follow a service-and-feeder design workflow that starts with load identification, moves through calculation logic, and ends with conductor and equipment decisions.', '{"necReferences":["220.40","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f888e5bf-2a46-488d-89cb-37dcd7c46990', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 2, 'paragraph', 'Why this matters', 'Master-level exams reward process discipline. These questions are less about one isolated section and more about whether you can move through the design path without skipping a step.', 'Master-level exams reward process discipline. These questions are less about one isolated section and more about whether you can move through the design path without skipping a step.', '{"necReferences":["220.40","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a0e4eb4d-516b-4d26-9370-82b9ce282537', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 3, 'paragraph', 'Core explanation', 'Service and feeder design starts with understanding the occupancy, load types, and calculation method that applies. After that, the designer determines connected load, applies demand or optional rules where allowed, identifies the governing ampacity, and then selects conductors and equipment to match the final calculated load. Good workflow prevents rework because each later choice depends on the earlier load decision.', 'Service and feeder design starts with understanding the occupancy, load types, and calculation method that applies. After that, the designer determines connected load, applies demand or optional rules where allowed, identifies the governing ampacity, and then selects conductors and equipment to match the final calculated load. Good workflow prevents rework because each later choice depends on the earlier load decision.', '{"necReferences":["220.40","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cdb5033e-9f2a-411b-9f3d-01510bb0256a', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 4, 'paragraph', 'Key concepts', 'Do not start with a conductor size and work backward. Start with the load path. Separate lighting, receptacle, appliance, HVAC, motor, and noncoincident considerations as needed. Then decide whether the question is really about a service, a feeder, or both. Master-level accuracy comes from sequencing, not speed alone.', 'Do not start with a conductor size and work backward. Start with the load path. Separate lighting, receptacle, appliance, HVAC, motor, and noncoincident considerations as needed. Then decide whether the question is really about a service, a feeder, or both. Master-level accuracy comes from sequencing, not speed alone.', '{"necReferences":["220.40","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6a739d73-21bd-4d2a-bbca-f6ef616d8bd1', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 5, 'paragraph', 'NEC / code relevance', 'NEC 220.40 frames the calculation path for feeders and services. NEC 230.42 covers service-conductor ampacity requirements. Together they remind the reader that conductors are chosen after the correct load logic is established, not before.', 'NEC 220.40 frames the calculation path for feeders and services. NEC 230.42 covers service-conductor ampacity requirements. Together they remind the reader that conductors are chosen after the correct load logic is established, not before.', '{"necReferences":["220.40","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7265f527-a984-4047-9e7d-82c2979b5f36', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 6, 'paragraph', 'Practical example', 'A mixed-load building problem often tempts students to jump straight to conductor ampacity. The better move is to list the loads by category, identify any demand-factor rules that apply, add the controlling values, and only then move to service or feeder conductor sizing.', 'A mixed-load building problem often tempts students to jump straight to conductor ampacity. The better move is to list the loads by category, identify any demand-factor rules that apply, add the controlling values, and only then move to service or feeder conductor sizing.', '{"necReferences":["220.40","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4eaaca2d-0d8c-4ca0-a336-194c64627920', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 7, 'paragraph', 'Common mistakes', 'Master candidates still lose points by mixing service and feeder language or by skipping the question of which loads can be reduced. Another mistake is assuming the largest connected number must always control the final calculation without checking the demand rules.', 'Master candidates still lose points by mixing service and feeder language or by skipping the question of which loads can be reduced. Another mistake is assuming the largest connected number must always control the final calculation without checking the demand rules.', '{"necReferences":["220.40","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5c6c2a45-e7ab-490b-ba04-e3cf92bf524f', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 8, 'paragraph', 'Exam insight', 'Write a workflow on scratch paper before solving complex design questions. A short checklist such as identify loads, choose method, apply demand, size conductors keeps advanced problems from turning into messy guesses.', 'Write a workflow on scratch paper before solving complex design questions. A short checklist such as identify loads, choose method, apply demand, size conductors keeps advanced problems from turning into messy guesses.', '{"necReferences":["220.40","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ad254e6f-f0ba-46d0-9bc3-ebf5430878fc', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('14852a31-9f9c-4e2f-a0a6-46cbc7a24582', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 10, 'bullet', NULL, 'Design questions are workflow questions before they are conductor questions.', 'Design questions are workflow questions before they are conductor questions.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('524eb71b-632c-43d9-b1a5-5f1fd295d09e', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 11, 'bullet', NULL, 'Load identification comes before ampacity selection.', 'Load identification comes before ampacity selection.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('94667e88-e86c-441c-a909-6c2127d417c0', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 12, 'bullet', NULL, 'Service and feeder language should stay clearly separated.', 'Service and feeder language should stay clearly separated.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('854dc519-0a8f-4dc8-b793-9146f60a4596', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 13, 'bullet', NULL, 'Demand logic can change the answer path significantly.', 'Demand logic can change the answer path significantly.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('23d32f22-a13e-4c73-bba1-701237d4eb9e', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('08e58050-f505-4306-9d94-cd8cc18a3f8e', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 15, 'callout', 'Question 1', 'Why is starting with conductor size a weak approach to service design questions?', 'Why is starting with conductor size a weak approach to service design questions?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8a386291-7253-45d6-9fa0-822ee697e37d', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 16, 'callout', 'Question 2', 'What is the value of writing a workflow before solving a complex load problem?', 'What is the value of writing a workflow before solving a complex load problem?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ee41741f-3422-4e83-838c-13277b2d6307', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 17, 'callout', 'Question 3', 'How can confusing feeder language with service language affect the final answer?', 'How can confusing feeder language with service language affect the final answer?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8ac758ed-14d9-478f-9230-38f6f5b0f3cb', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 1, 'paragraph', 'Learning objective', 'Use NEC tables, notes, and exceptions more strategically so you can read advanced questions with better judgment and fewer avoidable misses.', 'Use NEC tables, notes, and exceptions more strategically so you can read advanced questions with better judgment and fewer avoidable misses.', '{"necReferences":["220.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0a98d759-1513-4771-9bb9-541b0db6771d', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 2, 'paragraph', 'Why this matters', 'Master exams often hide the real challenge in the small print. A student may know the main rule but still miss the problem by overlooking a table note, exception, or limitation that changes the result.', 'Master exams often hide the real challenge in the small print. A student may know the main rule but still miss the problem by overlooking a table note, exception, or limitation that changes the result.', '{"necReferences":["220.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('06275340-66a4-428b-8523-5495fa3e0b0e', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 3, 'paragraph', 'Core explanation', 'Tables organize complex information efficiently, but they only work when you read their titles, scope, notes, and conditions carefully. Notes and exceptions can narrow, expand, or redirect the answer path depending on the article. Advanced code work is not about reading faster. It is about reading more deliberately when the code starts layering conditions.', 'Tables organize complex information efficiently, but they only work when you read their titles, scope, notes, and conditions carefully. Notes and exceptions can narrow, expand, or redirect the answer path depending on the article. Advanced code work is not about reading faster. It is about reading more deliberately when the code starts layering conditions.', '{"necReferences":["220.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bf91127a-0bc5-4ca8-a0da-0297bb4eb44d', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 4, 'paragraph', 'Key concepts', 'A table value outside its stated conditions is not a valid answer. An exception is not a free shortcut; it applies only when its conditions are satisfied. Notes also need context. Some are informational and explanatory, while others are integral to how the table is read. Strong exam performance comes from treating every table like a small rule system, not a list of numbers.', 'A table value outside its stated conditions is not a valid answer. An exception is not a free shortcut; it applies only when its conditions are satisfied. Notes also need context. Some are informational and explanatory, while others are integral to how the table is read. Strong exam performance comes from treating every table like a small rule system, not a list of numbers.', '{"necReferences":["220.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('25140c51-1f5a-4635-9fc0-c2a2da96e85f', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 5, 'paragraph', 'NEC / code relevance', 'NEC 220.42 and NEC 310.16 are good examples of places where table reading and context matter. In both cases, the title and surrounding language control how the data is used. The advanced student reads the structure around the table, not just the cells inside it.', 'NEC 220.42 and NEC 310.16 are good examples of places where table reading and context matter. In both cases, the title and surrounding language control how the data is used. The advanced student reads the structure around the table, not just the cells inside it.', '{"necReferences":["220.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bd9c5ad0-5d21-4bd0-92aa-f783dcf7629d', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 6, 'paragraph', 'Practical example', 'A candidate may find the number they expected in a table and circle it too quickly. But if the problem conditions do not match the table assumptions, or if a note changes how the value is applied, that quick answer becomes the wrong answer with great confidence.', 'A candidate may find the number they expected in a table and circle it too quickly. But if the problem conditions do not match the table assumptions, or if a note changes how the value is applied, that quick answer becomes the wrong answer with great confidence.', '{"necReferences":["220.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a2e9cd4d-1d74-4193-81e3-9e010c3b34bc', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 7, 'paragraph', 'Common mistakes', 'The common mistake is tunnel vision. Students see a familiar table and stop reading. Another mistake is treating all notes the same instead of deciding whether the note is explanatory, limiting, or part of the application path.', 'The common mistake is tunnel vision. Students see a familiar table and stop reading. Another mistake is treating all notes the same instead of deciding whether the note is explanatory, limiting, or part of the application path.', '{"necReferences":["220.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6a3450bd-dc19-4718-8579-31de70e45fb7', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 8, 'paragraph', 'Exam insight', 'When a question includes a table citation, slow down on purpose. The time you spend reading the heading, note, or exception is often the time that protects you from a very expensive wrong answer.', 'When a question includes a table citation, slow down on purpose. The time you spend reading the heading, note, or exception is often the time that protects you from a very expensive wrong answer.', '{"necReferences":["220.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2164385c-124f-4f8e-b228-8ff8fb6189f9', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f70538ec-f9d1-4feb-9e2e-757bc47d2c54', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 10, 'bullet', NULL, 'A table must be read with its title, scope, and surrounding language.', 'A table must be read with its title, scope, and surrounding language.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f701e535-8a8c-4650-97d0-de9198b96606', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 11, 'bullet', NULL, 'Exceptions only apply when their conditions are actually met.', 'Exceptions only apply when their conditions are actually met.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6b4db509-e4cc-4446-9002-9e90cdacf9fc', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 12, 'bullet', NULL, 'Advanced exam problems often turn on the small print around a familiar rule.', 'Advanced exam problems often turn on the small print around a familiar rule.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ffe34d83-232d-40e5-a7c0-ab0b815ee6f4', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 13, 'bullet', NULL, 'Deliberate reading beats fast guessing on master-level code questions.', 'Deliberate reading beats fast guessing on master-level code questions.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('adeeabd9-23ff-4a58-a208-d974539b76da', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('76b33a6c-02b4-4c55-a2e6-018dadc2b466', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 15, 'callout', 'Question 1', 'Why is reading only the table values without the heading risky?', 'Why is reading only the table values without the heading risky?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0ebb0cfa-ea33-49c4-a08d-99ef3c82ff00', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 16, 'callout', 'Question 2', 'What is the difference between seeing a table and truly applying it correctly?', 'What is the difference between seeing a table and truly applying it correctly?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fa64caa6-b4ae-4118-816d-910126698e29', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 17, 'callout', 'Question 3', 'Why can a note or exception change the answer even when the main table looks familiar?', 'Why can a note or exception change the answer even when the main table looks familiar?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('94e3b647-5f84-47ee-bd9c-2d772e114ab1', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 1, 'paragraph', 'Learning objective', 'Work through the optional dwelling calculation method with better structure so you can decide what belongs in the calculation, what can be reduced, and what must still be carried at full value.', 'Work through the optional dwelling calculation method with better structure so you can decide what belongs in the calculation, what can be reduced, and what must still be carried at full value.', '{"necReferences":["220.82","220.53","220.54","220.60"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d1984a26-d7ad-4779-bd9d-773de0262afa', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 2, 'paragraph', 'Why this matters', 'Optional dwelling calculations are attractive because they can simplify service-sizing problems, but they also create mistakes when students apply the method too casually or mix it with standard-method logic.', 'Optional dwelling calculations are attractive because they can simplify service-sizing problems, but they also create mistakes when students apply the method too casually or mix it with standard-method logic.', '{"necReferences":["220.82"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('76d61431-bb28-4f9b-9c2f-0d6259a56015', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 3, 'paragraph', 'Core explanation', 'The optional dwelling calculation is a specific path allowed for qualifying dwelling-unit services and feeders. It is not a free-form shortcut. The method gathers the appropriate loads, applies the rule structure in the optional section, and then carries the result into conductor and equipment sizing. A strong solution depends on organizing the categories before any arithmetic begins.', 'The optional dwelling calculation is a specific path allowed for qualifying dwelling-unit services and feeders. It is not a free-form shortcut. The method gathers the appropriate loads, applies the rule structure in the optional section, and then carries the result into conductor and equipment sizing. A strong solution depends on organizing the categories before any arithmetic begins.', '{"necReferences":["220.82","230.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('53084514-6b7b-42a7-8ae4-de1999b759fd', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 4, 'paragraph', 'Key concepts', 'Know what qualifies as the dwelling load base, what appliance demand concepts may matter, what dryer and cooking rules may still shape the number, and when noncoincident treatment applies. The method is optional, but once the problem directs you there, the steps should stay consistent.', 'Know what qualifies as the dwelling load base, what appliance demand concepts may matter, what dryer and cooking rules may still shape the number, and when noncoincident treatment applies. The method is optional, but once the problem directs you there, the steps should stay consistent.', '{"necReferences":["220.53","220.54","220.60","220.82"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('aee99b86-c53a-44b1-a40a-10f33c6515ea', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 5, 'paragraph', 'NEC / code relevance', 'NEC 220.82 is the center of the method. NEC 220.53, 220.54, and 220.60 support common load-treatment issues that may influence the calculation. NEC 230.42 and 310.16 matter after the load is established because service or feeder conductor selection still has to follow the final ampacity result.', 'NEC 220.82 is the center of the method. NEC 220.53, 220.54, and 220.60 support common load-treatment issues that may influence the calculation. NEC 230.42 and 310.16 matter after the load is established because service or feeder conductor selection still has to follow the final ampacity result.', '{"necReferences":["220.53","220.54","220.60","220.82","230.42","310.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b3934628-462d-4358-9788-db8a368743b4', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 6, 'paragraph', 'Practical example', 'A dwelling calculation problem becomes much easier when the student separates general load, appliances, dryers, cooking equipment, and heating or cooling before combining anything. That list-building step is what keeps advanced questions from turning into arithmetic clutter.', 'A dwelling calculation problem becomes much easier when the student separates general load, appliances, dryers, cooking equipment, and heating or cooling before combining anything. That list-building step is what keeps advanced questions from turning into arithmetic clutter.', '{"necReferences":["220.82"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8f96c106-f08d-4f99-8dcc-f042bdfa5e2f', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 7, 'paragraph', 'Common mistakes', 'Students often blend standard-method habits into optional-method questions. Another mistake is failing to identify which loads are noncoincident or which loads should be handled as a distinct category before reduction logic is applied.', 'Students often blend standard-method habits into optional-method questions. Another mistake is failing to identify which loads are noncoincident or which loads should be handled as a distinct category before reduction logic is applied.', '{"necReferences":["220.60","220.82"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('886f1e63-f0da-4aae-adee-f49ee1247f0c', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 8, 'paragraph', 'Exam insight', 'Master-level dwelling questions reward clean setup. Use columns or short labels on scratch paper. The student with an organized load list will usually beat the student with better mental math but weaker structure.', 'Master-level dwelling questions reward clean setup. Use columns or short labels on scratch paper. The student with an organized load list will usually beat the student with better mental math but weaker structure.', '{"necReferences":["220.82","230.42"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6d1851ce-7496-4afc-8cbf-f22ac685e6f8', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3897ab15-336c-4a41-9ec7-7c6615d6d814', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 10, 'bullet', NULL, 'The optional dwelling calculation is a defined method, not a loose shortcut.', 'The optional dwelling calculation is a defined method, not a loose shortcut.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e8b0c27f-61b8-4a9c-aa21-c49ad65c1e2e', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 11, 'bullet', NULL, 'Organizing loads by category is the most important first step.', 'Organizing loads by category is the most important first step.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('737b0588-85df-4167-ad59-c2470e955304', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 12, 'bullet', NULL, 'Supporting sections can affect how individual dwelling loads are treated.', 'Supporting sections can affect how individual dwelling loads are treated.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d1298f5f-be65-434d-bd62-be5f02425540', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 13, 'bullet', NULL, 'Conductor selection still happens after the correct load result is found.', 'Conductor selection still happens after the correct load result is found.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('07d89fce-19a0-4483-ba3e-7be209056511', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9591d18a-ee2d-4d07-a521-87513e958b4c', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 15, 'callout', 'Question 1', 'Why is load organization so important before using the optional dwelling method?', 'Why is load organization so important before using the optional dwelling method?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2a3e0c41-7468-4460-ad87-d819fd756664', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 16, 'callout', 'Question 2', 'What is one way standard-method thinking can cause mistakes in an optional-calculation problem?', 'What is one way standard-method thinking can cause mistakes in an optional-calculation problem?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6ad0332e-9d8e-4943-bf2e-6d7dfba83d7d', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 17, 'callout', 'Question 3', 'After the optional calculation total is found, what design step still remains?', 'After the optional calculation total is found, what design step still remains?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('741e9bf8-f805-409d-a3de-7c02dcf74fdb', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 1, 'paragraph', 'Learning objective', 'Approach commercial demand and feeder-sizing questions with a sequence that separates receptacle demand, motor impact, and final feeder ampacity.', 'Approach commercial demand and feeder-sizing questions with a sequence that separates receptacle demand, motor impact, and final feeder ampacity.', '{"necReferences":["220.44","220.50","215.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3d27f99c-ba5b-4a67-ace6-9f305a235a33', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 2, 'paragraph', 'Why this matters', 'Commercial calculations combine several load types, which makes them easy to overcount or undercount. Master-level questions reward candidates who organize the load categories before they start doing arithmetic.', 'Commercial calculations combine several load types, which makes them easy to overcount or undercount. Master-level questions reward candidates who organize the load categories before they start doing arithmetic.', '{"necReferences":["220.44","220.50","215.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0932ff5f-82b8-4a3c-b41f-7b9b35198be7', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 3, 'paragraph', 'Core explanation', 'Commercial feeder sizing begins with connected load, but the categories do not all follow the same rule path. Receptacle loads may allow demand treatment under one section, while motor loads may change the feeder result for a different reason. Lighting, receptacles, and motors should be separated first, adjusted by their governing rules, and only then recombined into one feeder load.', 'Commercial feeder sizing begins with connected load, but the categories do not all follow the same rule path. Receptacle loads may allow demand treatment under one section, while motor loads may change the feeder result for a different reason. Lighting, receptacles, and motors should be separated first, adjusted by their governing rules, and only then recombined into one feeder load.', '{"necReferences":["220.44","220.50","215.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fe127af7-6254-48b0-a913-26a390e0a846', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 4, 'paragraph', 'Key concepts', 'A blanket multiplier is a warning sign in commercial work. Receptacle demand treatment is not the same thing as motor treatment, and neither one answers the final feeder-conductor choice by itself. Strong master-level solutions show a clean category list, the rule that controls each category, and the final recombined load used for feeder ampacity.', 'A blanket multiplier is a warning sign in commercial work. Receptacle demand treatment is not the same thing as motor treatment, and neither one answers the final feeder-conductor choice by itself. Strong master-level solutions show a clean category list, the rule that controls each category, and the final recombined load used for feeder ampacity.', '{"necReferences":["220.44","220.50","215.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bae6b79e-d251-4cdb-8545-de680826cd75', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 5, 'paragraph', 'NEC / code relevance', 'NEC 220.44 addresses receptacle-load demand factors. NEC 220.50 addresses motor loads in Article 220 calculations. NEC 215.2 covers feeder conductor ampacity. The code path matters because the motor effect and the conductor-selection step are related, but they are not the same decision.', 'NEC 220.44 addresses receptacle-load demand factors. NEC 220.50 addresses motor loads in Article 220 calculations. NEC 215.2 covers feeder conductor ampacity. The code path matters because the motor effect and the conductor-selection step are related, but they are not the same decision.', '{"necReferences":["220.44","220.50","215.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1c06424e-b541-46ef-ac64-c89327a4293e', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 6, 'paragraph', 'Practical example', 'Imagine a small office suite with lighting, general receptacles, and a motor-driven air-handling unit. A weak solution lumps the whole job together and reaches for one demand factor. A stronger solution isolates the receptacle treatment, evaluates the motor impact separately, and then carries the adjusted total into feeder sizing under the feeder-ampacity rule.', 'Imagine a small office suite with lighting, general receptacles, and a motor-driven air-handling unit. A weak solution lumps the whole job together and reaches for one demand factor. A stronger solution isolates the receptacle treatment, evaluates the motor impact separately, and then carries the adjusted total into feeder sizing under the feeder-ampacity rule.', '{"necReferences":["220.44","220.50","215.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('395f1950-9dbb-47f5-9d63-729e17faa5b7', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 7, 'paragraph', 'Common mistakes', 'The biggest mistake is treating all commercial loads like one pile. Another is applying receptacle-style demand thinking to motor load treatment, or selecting feeder conductors before the adjusted category totals are actually settled.', 'The biggest mistake is treating all commercial loads like one pile. Another is applying receptacle-style demand thinking to motor load treatment, or selecting feeder conductors before the adjusted category totals are actually settled.', '{"necReferences":["220.44","220.50","215.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('63a5ddc3-4493-4b79-95dd-d54f20d03c42', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 8, 'paragraph', 'Exam insight', 'If a commercial problem feels messy, stop and build a category list on scratch paper before touching the math. On master exams, the candidate with the clearer workflow usually beats the candidate with the faster calculator.', 'If a commercial problem feels messy, stop and build a category list on scratch paper before touching the math. On master exams, the candidate with the clearer workflow usually beats the candidate with the faster calculator.', '{"necReferences":["220.44","220.50","215.2"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d37420b5-f8bd-4a0e-bb9e-229cadbcc323', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('267859e3-7520-47ac-b2fe-9b64908751fa', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 10, 'bullet', NULL, 'Commercial feeder sizing starts with load categories, not blanket math.', 'Commercial feeder sizing starts with load categories, not blanket math.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8fe978cd-928d-4d4c-8825-20baee4495f9', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 11, 'bullet', NULL, 'Receptacle demand treatment and motor treatment can affect the total for different reasons.', 'Receptacle demand treatment and motor treatment can affect the total for different reasons.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('738ecea6-e6c5-4ba8-a60e-d20f1efac8bc', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 12, 'bullet', NULL, 'Feeder conductor sizing happens after the adjusted load path is established.', 'Feeder conductor sizing happens after the adjusted load path is established.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('791f4cfc-a8e3-415b-814e-b6245361e891', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 13, 'bullet', NULL, 'An organized category workflow is one of the best master-level exam advantages.', 'An organized category workflow is one of the best master-level exam advantages.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4cdc11b6-86c3-4749-866a-ba880dd14bfb', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('01019f5c-d052-4e34-aabc-55ab2e677f1c', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 15, 'callout', 'Question 1', 'Why is it risky to treat lighting, receptacles, and motors as one undifferentiated commercial load?', 'Why is it risky to treat lighting, receptacles, and motors as one undifferentiated commercial load?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ec46816e-20f7-4133-abfe-6f2a3cae48c2', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 16, 'callout', 'Question 2', 'What makes motor treatment different from ordinary receptacle demand treatment in a feeder problem?', 'What makes motor treatment different from ordinary receptacle demand treatment in a feeder problem?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('53cb5a7d-b979-45ea-a7fe-572b28a80699', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 17, 'callout', 'Question 3', 'At what point in the workflow should feeder conductor sizing happen?', 'At what point in the workflow should feeder conductor sizing happen?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7816963f-5203-4801-872b-a1f065ca4ccd', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 1, 'paragraph', 'Learning objective', 'Classify hazardous locations more confidently by understanding the logic behind class, division, and zone language and the role of protection techniques.', 'Classify hazardous locations more confidently by understanding the logic behind class, division, and zone language and the role of protection techniques.', '{"necReferences":["500.5","500.7"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f888fda7-e77f-404b-8ffc-0968def81763', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 2, 'paragraph', 'Why this matters', 'Hazardous-location questions feel intimidating because the vocabulary is dense. But once you understand what is being classified and why, the topic becomes much more teachable and much less mysterious.', 'Hazardous-location questions feel intimidating because the vocabulary is dense. But once you understand what is being classified and why, the topic becomes much more teachable and much less mysterious.', '{"necReferences":["500.5","500.7"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0999917b-d8f4-4b82-ab02-7bdcb37cbd2e', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 3, 'paragraph', 'Core explanation', 'Hazardous locations are classified based on the type of material present and the likelihood that it may be present in an ignitable concentration. Class points to the broad hazard type, while division or zone language refines the exposure condition. Equipment and wiring methods are then selected based on that classification so the installation does not become the ignition source.', 'Hazardous locations are classified based on the type of material present and the likelihood that it may be present in an ignitable concentration. Class points to the broad hazard type, while division or zone language refines the exposure condition. Equipment and wiring methods are then selected based on that classification so the installation does not become the ignition source.', '{"necReferences":["500.5","500.7"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9e80654d-67f0-491f-b2c1-240cd055faff', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 4, 'paragraph', 'Key concepts', 'Do not start with the equipment. Start with the atmosphere or material. Then determine whether the condition is normal, abnormal, continuous, or occasional according to the classification system in use. Protection techniques matter because different locations permit different approaches to controlling ignition risk.', 'Do not start with the equipment. Start with the atmosphere or material. Then determine whether the condition is normal, abnormal, continuous, or occasional according to the classification system in use. Protection techniques matter because different locations permit different approaches to controlling ignition risk.', '{"necReferences":["500.5","500.7","505.9"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d298a805-b247-4adf-a1a5-d7a7f3da2dc9', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 5, 'paragraph', 'NEC / code relevance', 'NEC 500.5 addresses classifications. NEC 500.7 addresses protection techniques. Articles 501, 502, and 505 then apply those ideas to specific location types and permitted equipment and wiring methods. This is a classic hierarchy-and-application exam topic.', 'NEC 500.5 addresses classifications. NEC 500.7 addresses protection techniques. Articles 501, 502, and 505 then apply those ideas to specific location types and permitted equipment and wiring methods. This is a classic hierarchy-and-application exam topic.', '{"necReferences":["500.5","500.7","501.10","501.15","501.125","502.10","505.9"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1df093c3-ba14-4f2e-bd34-19fe662a0691', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 6, 'paragraph', 'Practical example', 'A classified-location question may mention vapors, dust, or fibers and then ask about wiring method or equipment type. The right move is to classify the location first. If you skip that step and jump to materials, you usually choose the wrong code path.', 'A classified-location question may mention vapors, dust, or fibers and then ask about wiring method or equipment type. The right move is to classify the location first. If you skip that step and jump to materials, you usually choose the wrong code path.', '{"necReferences":["500.5","501.10","502.10","505.9"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fbce982e-b765-4eb0-88b8-0f4827f4c098', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 7, 'paragraph', 'Common mistakes', 'Students often memorize a few article numbers and try to answer from memory alone. That breaks down quickly when the problem changes from one hazard type to another. Another mistake is mixing division language and zone language without noticing the question''s framework.', 'Students often memorize a few article numbers and try to answer from memory alone. That breaks down quickly when the problem changes from one hazard type to another. Another mistake is mixing division language and zone language without noticing the question''s framework.', '{"necReferences":["500.5","500.7","505.9"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6d124ec7-abd8-431e-ae16-3926e9a118e1', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 8, 'paragraph', 'Exam insight', 'On master exams, the winning skill is classification discipline. Classify the hazard first, identify the framework second, and only then move to wiring methods, seals, motors, or equipment selection.', 'On master exams, the winning skill is classification discipline. Classify the hazard first, identify the framework second, and only then move to wiring methods, seals, motors, or equipment selection.', '{"necReferences":["500.5","500.7"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e5b2b677-6ea5-4aa1-beea-5a14e698694a', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e005cf4a-0000-4f95-b854-5750c79526e6', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 10, 'bullet', NULL, 'Hazardous-location questions should start with classification, not equipment choice.', 'Hazardous-location questions should start with classification, not equipment choice.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b208b3d9-7270-4424-8bb1-e68c78d93e1d', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 11, 'bullet', NULL, 'Class identifies the broad hazard, while division or zone refines the condition.', 'Class identifies the broad hazard, while division or zone refines the condition.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b7c42f62-244d-4116-9f7a-e072be242e3a', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 12, 'bullet', NULL, 'Protection techniques are part of the code path, not side notes.', 'Protection techniques are part of the code path, not side notes.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a569f31f-6c36-43bd-86d9-82e91cbc6b54', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 13, 'bullet', NULL, 'Mixing division and zone frameworks is a common exam mistake.', 'Mixing division and zone frameworks is a common exam mistake.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2f7cd6bf-7cdd-4ec4-8edb-34bc5fd0d0df', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c0382740-84d1-41ef-b2f6-1e7074d32884', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 15, 'callout', 'Question 1', 'Why is equipment selection the wrong first step in a hazardous-location question?', 'Why is equipment selection the wrong first step in a hazardous-location question?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6109d8dd-0571-46fd-b291-3f891a4f2db3', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 16, 'callout', 'Question 2', 'What does the class tell you in a hazardous-location classification?', 'What does the class tell you in a hazardous-location classification?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7de93787-94a6-40c4-8e91-5b8cb64c940f', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 17, 'callout', 'Question 3', 'Why is it important to notice whether the problem uses division language or zone language?', 'Why is it important to notice whether the problem uses division language or zone language?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a8a76ea1-275c-4485-8905-f742b4b63044', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 1, 'paragraph', 'Learning objective', 'Evaluate motors, sealing fittings, and equipment choices in classified areas by tying each decision back to the location classification and protection method.', 'Evaluate motors, sealing fittings, and equipment choices in classified areas by tying each decision back to the location classification and protection method.', '{"necReferences":["501.15","501.125"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3596a358-59e2-46b8-830f-c39d732b45da', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 2, 'paragraph', 'Why this matters', 'After classification, master-level questions usually shift into application. That is where many candidates lose points. They know the area is hazardous, but they cannot explain why a certain motor, enclosure, or sealing approach is or is not acceptable.', 'After classification, master-level questions usually shift into application. That is where many candidates lose points. They know the area is hazardous, but they cannot explain why a certain motor, enclosure, or sealing approach is or is not acceptable.', '{"necReferences":["501.15","501.125"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('21f9e27f-1660-4041-88bd-d7fdc3371cff', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 3, 'paragraph', 'Core explanation', 'In classified areas, equipment selection is controlled by the location classification and the approved protection approach. Motors, raceway seals, and enclosures must work together to reduce the chance of ignition. Sealing fittings are used where the code requires control of gas, vapor, or pressure movement through the raceway system. Motor suitability depends on whether the motor and its protection method match the classified location.', 'In classified areas, equipment selection is controlled by the location classification and the approved protection approach. Motors, raceway seals, and enclosures must work together to reduce the chance of ignition. Sealing fittings are used where the code requires control of gas, vapor, or pressure movement through the raceway system. Motor suitability depends on whether the motor and its protection method match the classified location.', '{"necReferences":["501.15","501.125"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ce00605f-d0be-442d-bc33-2ec822987ff4', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 4, 'paragraph', 'Key concepts', 'Do not treat seals like ordinary fittings or as general-purpose moisture control. Their role is tied to hazard control. Motors also cannot be judged by appearance alone. The nameplate, approval, and protection approach have to match the classified condition. In hazardous locations, application always follows classification.', 'Do not treat seals like ordinary fittings or as general-purpose moisture control. Their role is tied to hazard control. Motors also cannot be judged by appearance alone. The nameplate, approval, and protection approach have to match the classified condition. In hazardous locations, application always follows classification.', '{"necReferences":["501.15","501.125"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4631305d-1f41-4d7f-9cd9-ab9c9c3a0f09', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 5, 'paragraph', 'NEC / code relevance', 'NEC 501.15 covers sealing and drainage in Class I locations. NEC 501.125 covers motors in those locations. These sections are often tested together because a problem can begin with classification language and end by asking what equipment arrangement actually makes sense.', 'NEC 501.15 covers sealing and drainage in Class I locations. NEC 501.125 covers motors in those locations. These sections are often tested together because a problem can begin with classification language and end by asking what equipment arrangement actually makes sense.', '{"necReferences":["501.15","501.125"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a8a49828-cf65-4e48-913f-41e0554596bb', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 6, 'paragraph', 'Practical example', 'A Class I pump area question may describe a motor, a raceway leaving the area, and a sealing fitting in the same paragraph. The exam is not asking for random article recall. It is asking whether you understand that the motor must be suitable for the classified location and that the seal serves a specific hazard-control purpose where the code requires it.', 'A Class I pump area question may describe a motor, a raceway leaving the area, and a sealing fitting in the same paragraph. The exam is not asking for random article recall. It is asking whether you understand that the motor must be suitable for the classified location and that the seal serves a specific hazard-control purpose where the code requires it.', '{"necReferences":["501.15","501.125"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5008b089-592d-4a40-ae22-6c53da205c80', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 7, 'paragraph', 'Common mistakes', 'Students often place seals anywhere they seem helpful instead of where the code requires them. Another mistake is choosing a familiar industrial motor without asking whether its protection method and approval match the classified location being described.', 'Students often place seals anywhere they seem helpful instead of where the code requires them. Another mistake is choosing a familiar industrial motor without asking whether its protection method and approval match the classified location being described.', '{"necReferences":["501.15","501.125"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('df8c3308-ce24-4fcc-b751-0f0caa9db589', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 8, 'paragraph', 'Exam insight', 'When a question mentions both a motor and a seal, connect both decisions back to the classified hazard first. The answer usually becomes clearer when you think about ignition control instead of memorizing article numbers in isolation.', 'When a question mentions both a motor and a seal, connect both decisions back to the classified hazard first. The answer usually becomes clearer when you think about ignition control instead of memorizing article numbers in isolation.', '{"necReferences":["501.15","501.125"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3bf760a6-6480-4077-8529-f43752574343', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('070f64e6-540c-4547-bba1-0a1466460f52', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 10, 'bullet', NULL, 'Equipment selection in classified areas always follows the location classification first.', 'Equipment selection in classified areas always follows the location classification first.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('01ef00d3-5aaa-4c9e-ab10-e64095d07fc7', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 11, 'bullet', NULL, 'Sealing fittings are hazard-control devices, not generic raceway accessories.', 'Sealing fittings are hazard-control devices, not generic raceway accessories.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9bc2df01-3a40-42a6-9e65-c07a4d120c27', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 12, 'bullet', NULL, 'Motor suitability depends on approval and protection method, not on appearance or brand familiarity.', 'Motor suitability depends on approval and protection method, not on appearance or brand familiarity.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('84f6d6ba-ca85-4060-b79b-4514218c4cdc', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 13, 'bullet', NULL, 'Purpose-based reasoning is the safest way to solve hazardous-location questions.', 'Purpose-based reasoning is the safest way to solve hazardous-location questions.', '{}'::jsonb);
