INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a5d8f973-ab5c-4e0d-892e-4dd7aff073e8', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 15, 'callout', 'Question 1', 'Why is a sealing fitting not just another ordinary raceway fitting in a classified location?', 'Why is a sealing fitting not just another ordinary raceway fitting in a classified location?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0a96f782-a9b4-40ca-9143-03d377d543b2', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 16, 'callout', 'Question 2', 'What should determine whether a motor is suitable for a hazardous location?', 'What should determine whether a motor is suitable for a hazardous location?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('22b8ffb1-c547-43fc-9642-c72f57aa8d04', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 17, 'callout', 'Question 3', 'When a classified-area question mentions both motors and seals, what should you connect them back to first?', 'When a classified-area question mentions both motors and seals, what should you connect them back to first?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('44aec799-5525-4a7a-bc62-da0a6f381412', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 1, 'paragraph', 'Learning objective', 'Read NEC 90.1, 90.3, and Article 100 with a master-level mindset so you can use purpose, hierarchy, and definitions to settle difficult code questions more efficiently.', 'Read NEC 90.1, 90.3, and Article 100 with a master-level mindset so you can use purpose, hierarchy, and definitions to settle difficult code questions more efficiently.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('260ca5b4-a014-4d0c-9706-fd3ca815d47e', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 2, 'paragraph', 'Why this matters', 'At the master level, the code is not just a list of isolated rules. It is a structured document with purpose, hierarchy, and defined language. These opening sections help you reason through hard questions instead of just hunting citations.', 'At the master level, the code is not just a list of isolated rules. It is a structured document with purpose, hierarchy, and defined language. These opening sections help you reason through hard questions instead of just hunting citations.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a58f435f-c3f3-40e2-aaa8-7c2e58c67175', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 3, 'paragraph', 'Core explanation', 'NEC 90.1 reminds you what the code is trying to do: provide practical safeguarding. NEC 90.3 shows how the document is arranged and how later special rules may modify general rules. Article 100 controls the meaning of defined terms used throughout the code. Together, these sections help you decide not only where to search, but how to interpret what you find.', 'NEC 90.1 reminds you what the code is trying to do: provide practical safeguarding. NEC 90.3 shows how the document is arranged and how later special rules may modify general rules. Article 100 controls the meaning of defined terms used throughout the code. Together, these sections help you decide not only where to search, but how to interpret what you find.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2eb6cd92-8ea5-4bb4-b5ec-065d0f2c8c0f', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 4, 'paragraph', 'Key concepts', 'Purpose matters because the NEC is not intended as a design manual for every good outcome. Hierarchy matters because a general answer may change when a special rule applies. Definitions matter because common-language assumptions often do not match code-language meaning. Master-level reading starts with those three anchors.', 'Purpose matters because the NEC is not intended as a design manual for every good outcome. Hierarchy matters because a general answer may change when a special rule applies. Definitions matter because common-language assumptions often do not match code-language meaning. Master-level reading starts with those three anchors.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c7f60a1e-c6e8-4732-a988-b05d6f7dcb7b', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 5, 'paragraph', 'NEC / code relevance', 'These are the sections that shape the way you read the rest of the NEC. They are not just introductory pages. They are interpretation tools. When a problem is ambiguous, these sections often point you toward the right search path and the right reading discipline.', 'These are the sections that shape the way you read the rest of the NEC. They are not just introductory pages. They are interpretation tools. When a problem is ambiguous, these sections often point you toward the right search path and the right reading discipline.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('277349a4-e992-4cdc-ad69-77c0854f56c1', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 6, 'paragraph', 'Practical example', 'An advanced code dispute may look technical on the surface, but the real issue can be whether a term is defined, whether a special rule controls, or whether the code is being stretched beyond its stated purpose. That is why experienced code users keep coming back to these sections.', 'An advanced code dispute may look technical on the surface, but the real issue can be whether a term is defined, whether a special rule controls, or whether the code is being stretched beyond its stated purpose. That is why experienced code users keep coming back to these sections.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('498ea6d0-7acb-4d46-bf96-06085f254d58', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 7, 'paragraph', 'Common mistakes', 'A common mistake is treating Article 100 as beginner material instead of a master-level interpretation tool. Another is using NEC purpose language to justify a preferred design choice when the enforceable text points somewhere else.', 'A common mistake is treating Article 100 as beginner material instead of a master-level interpretation tool. Another is using NEC purpose language to justify a preferred design choice when the enforceable text points somewhere else.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9a645c21-62c3-485c-b19d-e7a7589e5905', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 8, 'paragraph', 'Exam insight', 'Master exams often reward the candidate who can reason from code structure, not just quote a section number. If a question feels vague, check whether purpose, hierarchy, or a defined term is the real hinge point.', 'Master exams often reward the candidate who can reason from code structure, not just quote a section number. If a question feels vague, check whether purpose, hierarchy, or a defined term is the real hinge point.', '{"necReferences":["90.1","90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c9592c4a-c12b-4a7b-a6d9-780849606651', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('361a8741-5001-42ac-8e82-f95cad97cb31', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 10, 'bullet', NULL, 'Purpose, hierarchy, and definitions are interpretation tools.', 'Purpose, hierarchy, and definitions are interpretation tools.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6a76b7cc-3f5d-4e11-ac55-310278c26475', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 11, 'bullet', NULL, 'Article 100 remains important even at the master level.', 'Article 100 remains important even at the master level.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1821c35e-5df4-40df-99ee-aeab329882d7', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 12, 'bullet', NULL, 'A difficult question may turn on structure before it turns on technical detail.', 'A difficult question may turn on structure before it turns on technical detail.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e0cab561-5c82-41ab-8186-ccb81f873948', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 13, 'bullet', NULL, 'Strong code reading uses these opening sections to frame the rest of the search.', 'Strong code reading uses these opening sections to frame the rest of the search.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5cae0067-2b59-44f0-85ea-bb6fcd2fd1a7', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ad4ec699-8f6d-4acf-b52e-e1add4324925', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 15, 'callout', 'Question 1', 'Why are NEC 90.1 and 90.3 more than introductory material?', 'Why are NEC 90.1 and 90.3 more than introductory material?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2c612145-fa2b-49e1-9249-d24d08583b34', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 16, 'callout', 'Question 2', 'How can Article 100 affect an advanced code question?', 'How can Article 100 affect an advanced code question?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('98332759-24b3-4498-9922-9462d6d2e437', 'f1b37758-4019-4b8e-8264-ed5a2a5c798f', 17, 'callout', 'Question 3', 'What should you ask when a code question feels vague or conflicted?', 'What should you ask when a code question feels vague or conflicted?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ffbf96b6-3070-4d50-9941-d08aecf936cb', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 1, 'paragraph', 'Learning objective', 'Recognize when the NEC is only part of the answer and explain how authority, approval, listed-equipment instructions, and adopted local conditions can change the practical outcome.', 'Recognize when the NEC is only part of the answer and explain how authority, approval, listed-equipment instructions, and adopted local conditions can change the practical outcome.', '{"necReferences":["90.4","110.2","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3ca57ed4-d44a-42ac-b6fa-1f771d37eb25', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 2, 'paragraph', 'Why this matters', 'Master electricians are expected to think beyond a single section citation. Real projects involve code adoption, authority-having-jurisdiction decisions, listed-equipment instructions, and local processes that affect what actually gets approved and installed.', 'Master electricians are expected to think beyond a single section citation. Real projects involve code adoption, authority-having-jurisdiction decisions, listed-equipment instructions, and local processes that affect what actually gets approved and installed.', '{"necReferences":["90.4","110.2","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cf677c4f-5376-4579-bbba-9ea2bd5cc864', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 3, 'paragraph', 'Core explanation', 'The NEC is central, but it is not the whole compliance universe. Jurisdictions adopt editions and may apply local amendments. The authority having jurisdiction interprets and enforces the adopted rules. Listed equipment must still be installed and used according to its approval and instructions. A complete answer often requires more than reading one NEC section in isolation.', 'The NEC is central, but it is not the whole compliance universe. Jurisdictions adopt editions and may apply local amendments. The authority having jurisdiction interprets and enforces the adopted rules. Listed equipment must still be installed and used according to its approval and instructions. A complete answer often requires more than reading one NEC section in isolation.', '{"necReferences":["90.4","110.2","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c23205fc-b073-44d5-8603-62212d9559d2', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 4, 'paragraph', 'Key concepts', 'Code adoption, approval, listing, and enforcement all influence the real-world answer. A correct national-core NEC citation may still need adjustment if the jurisdiction uses a different adopted edition or local amendment. Even then, listed-equipment instructions still matter. Strong master-level judgment means knowing whether the missing piece is technical, procedural, or both.', 'Code adoption, approval, listing, and enforcement all influence the real-world answer. A correct national-core NEC citation may still need adjustment if the jurisdiction uses a different adopted edition or local amendment. Even then, listed-equipment instructions still matter. Strong master-level judgment means knowing whether the missing piece is technical, procedural, or both.', '{"necReferences":["90.4","110.2","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2c9d7c20-8b2b-4770-bd0f-e092f6e8babc', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 5, 'paragraph', 'NEC / code relevance', 'NEC 90.4 addresses interpretation and enforcement by the authority having jurisdiction. NEC 110.2 emphasizes approval. NEC 110.3(B) ties listed equipment to its installation and use instructions. Together they remind advanced users that compliance is technical, procedural, and product-specific at the same time.', 'NEC 90.4 addresses interpretation and enforcement by the authority having jurisdiction. NEC 110.2 emphasizes approval. NEC 110.3(B) ties listed equipment to its installation and use instructions. Together they remind advanced users that compliance is technical, procedural, and product-specific at the same time.', '{"necReferences":["90.4","110.2","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4fb54f58-0ebb-4232-b6c7-a9126a75dbc9', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 6, 'paragraph', 'Practical example', 'A design may look acceptable under a general NEC rule, but the final answer can still change if the jurisdiction has adopted a different edition, the inspector requires a documented approval path, or the listed equipment instructions control how the product must be mounted, protected, or terminated. Master-level questions often compress all of that into one short scenario.', 'A design may look acceptable under a general NEC rule, but the final answer can still change if the jurisdiction has adopted a different edition, the inspector requires a documented approval path, or the listed equipment instructions control how the product must be mounted, protected, or terminated. Master-level questions often compress all of that into one short scenario.', '{"necReferences":["90.4","110.2","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fd2484d1-b331-49f3-85b2-28964e6954ec', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 7, 'paragraph', 'Common mistakes', 'A common mistake is treating one NEC citation like the last word in every jurisdiction. Another is ignoring listed-equipment instructions because the installer thinks broad code language is enough. Approval and listing instructions can still decide the final outcome.', 'A common mistake is treating one NEC citation like the last word in every jurisdiction. Another is ignoring listed-equipment instructions because the installer thinks broad code language is enough. Approval and listing instructions can still decide the final outcome.', '{"necReferences":["90.4","110.2","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('280c04fe-d305-4137-b66c-08d84b264051', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 8, 'paragraph', 'Exam insight', 'When a question asks who decides, who approves, or what happens when local adoption differs, the exam is testing maturity of judgment. The best answer respects both code knowledge and the authority structure around it.', 'When a question asks who decides, who approves, or what happens when local adoption differs, the exam is testing maturity of judgment. The best answer respects both code knowledge and the authority structure around it.', '{"necReferences":["90.4","110.2","110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4117c277-b14d-4fc8-9b46-49879d963409', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3de434ff-02cb-457f-afd6-28f4f5ebbb70', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 10, 'bullet', NULL, 'The NEC is central, but local adoption and approval still affect the final answer.', 'The NEC is central, but local adoption and approval still affect the final answer.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fda33529-7b4e-4008-bc91-e58e23de5d62', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 11, 'bullet', NULL, 'The authority having jurisdiction plays a real role in interpretation and enforcement.', 'The authority having jurisdiction plays a real role in interpretation and enforcement.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1b7cf046-6273-4a79-acb8-77f14dbe31b0', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 12, 'bullet', NULL, 'Listed-equipment instructions remain important even when the NEC path seems clear.', 'Listed-equipment instructions remain important even when the NEC path seems clear.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0849094d-ba4e-4b66-be33-1e8c359054c8', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 13, 'bullet', NULL, 'Master-level judgment includes knowing when the answer is technical, procedural, product-specific, or all three.', 'Master-level judgment includes knowing when the answer is technical, procedural, product-specific, or all three.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dc62aa2a-6426-4f13-b45d-e034b64d7714', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 14, 'heading', NULL, 'Knowledge Check', 'Knowledge Check', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('79d02d6c-8e0c-4ee2-97de-157e58d931f1', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 15, 'callout', 'Question 1', 'Why can a correct NEC citation still be incomplete in a real jurisdiction?', 'Why can a correct NEC citation still be incomplete in a real jurisdiction?', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('705182be-0c99-4eb1-8601-c381dae4b184', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 16, 'callout', 'Question 2', 'What role does the authority having jurisdiction play in code application?', 'What role does the authority having jurisdiction play in code application?', '{}'::jsonb);
