INSERT INTO nec_entries (id, reference_code, title, canonical_text_excerpt, simplified_summary, edition, topic_notes, is_active) VALUES ('270e5bb0-3145-4b22-a13d-cafaff6322f9', '110.1', 'Scope', NULL, 'Introduces the general requirements that apply to electrical installations and equipment.', 'National core; verify adopted cycle', NULL, TRUE);
INSERT INTO nec_entries (id, reference_code, title, canonical_text_excerpt, simplified_summary, edition, topic_notes, is_active) VALUES ('93c9a873-e535-4561-8448-67c2aaabad8d', '110.2', 'Approval', NULL, 'Requires equipment and conductors to be acceptable to the authority having jurisdiction.', 'National core; verify adopted cycle', NULL, TRUE);
INSERT INTO nec_entries (id, reference_code, title, canonical_text_excerpt, simplified_summary, edition, topic_notes, is_active) VALUES ('c3a36319-8ed5-4d85-8241-1079468aa48b', '110.26', 'Spaces About Electrical Equipment', NULL, 'Covers working-space, access, and dedicated-space rules around electrical equipment.', 'National core; verify adopted cycle', NULL, TRUE);
INSERT INTO nec_entries (id, reference_code, title, canonical_text_excerpt, simplified_summary, edition, topic_notes, is_active) VALUES ('e726b731-00b8-4db4-a405-c73d7f098164', '110.27', 'Guarding of Live Parts', NULL, 'Requires live parts to be guarded against accidental contact.', 'National core; verify adopted cycle', NULL, TRUE);
INSERT INTO nec_entries (id, reference_code, title, canonical_text_excerpt, simplified_summary, edition, topic_notes, is_active) VALUES ('84080d92-f90f-4e68-ba06-357c33c4201d', '110.3(B)', 'Installation and Use', NULL, 'Requires listed or labeled equipment to be installed and used according to its instructions.', 'National core; verify adopted cycle', NULL, TRUE);
INSERT INTO nec_entries (id, reference_code, title, canonical_text_excerpt, simplified_summary, edition, topic_notes, is_active) VALUES ('b0d52ce9-236a-49c8-a8d6-eed66d9ec0c7', '110.4', 'Voltages', NULL, 'Addresses voltage considerations that affect installation and equipment application.', 'National core; verify adopted cycle', NULL, TRUE);
INSERT INTO nec_entries (id, reference_code, title, canonical_text_excerpt, simplified_summary, edition, topic_notes, is_active) VALUES ('709fab09-b172-4df8-84af-da9c19ca7e68', '210.11', 'Branch Circuits Required', NULL, 'Identifies required dwelling-unit branch circuits such as small-appliance, laundry, and bathroom circuits.', 'National core; verify adopted cycle', NULL, TRUE);
INSERT INTO nec_entries (id, reference_code, title, canonical_text_excerpt, simplified_summary, edition, topic_notes, is_active) VALUES ('ec1a6935-fdc7-4284-a868-5e8161bc3d34', '210.19(A)(1)', 'Branch-Circuit Conductor Sizing', NULL, 'Sets minimum conductor ampacity for branch circuits and continuous loads.', 'National core; verify adopted cycle', NULL, TRUE);
